import { useState, useCallback, forwardRef, type CSSProperties } from 'react';

/** Trading mode. */
export type TradingMode = 'paper' | 'live';

interface TradingModeToggleProps {
  /** Current trading mode. */
  mode: TradingMode;
  /** Called when the user confirms a mode change. */
  onModeChange: (mode: TradingMode) => void;
  /** Exchange name shown in the confirmation dialog. */
  exchange: string;
}

/* -------------------------------------------------------------------------- */
/*  Styles                                                                    */
/* -------------------------------------------------------------------------- */

const STYLE_ID = 'ts-trading-mode-toggle-styles';

function ensureTradingModeStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-trading-mode-toggle] {
      display: flex;
      align-items: center;
      gap: var(--ts-space-2, 8px);
      padding: 6px var(--ts-space-3, 12px);
      border-radius: var(--ts-radius-sm, 6px);
      font-size: var(--ts-font-xs, 11px);
      font-weight: 700;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      cursor: pointer;
      transition: all 120ms;
      user-select: none;
    }
    [data-ts-trading-mode-toggle][data-mode="paper"] {
      background: rgba(34, 197, 94, 0.12);
      border: 2px solid var(--ts-color-bullish, #22c55e);
      color: var(--ts-color-bullish, #22c55e);
    }
    [data-ts-trading-mode-toggle][data-mode="live"] {
      background: rgba(249, 115, 22, 0.12);
      border: 2px solid #f97316;
      color: #f97316;
    }
    [data-ts-trading-mode-badge] {
      padding: 1px 6px;
      border-radius: 3px;
      font-size: 10px;
      font-weight: 800;
    }
    [data-ts-trading-mode-badge][data-mode="paper"] {
      background: var(--ts-color-bullish, #22c55e);
      color: #000;
    }
    [data-ts-trading-mode-badge][data-mode="live"] {
      background: #f97316;
      color: #000;
    }
    [data-ts-confirm-overlay] {
      position: fixed;
      inset: 0;
      background: rgba(0, 0, 0, 0.65);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 10000;
    }
    [data-ts-confirm-dialog] {
      background: var(--ts-surface-primary, #0f0f17);
      border: 1px solid #f97316;
      border-radius: var(--ts-radius-md, 10px);
      padding: var(--ts-space-4, 16px);
      max-width: 360px;
      width: 90%;
      display: flex;
      flex-direction: column;
      gap: var(--ts-space-3, 12px);
    }
    [data-ts-confirm-title] {
      font-size: var(--ts-font-md, 14px);
      font-weight: 700;
      color: #f97316;
      text-transform: uppercase;
      letter-spacing: 0.04em;
    }
    [data-ts-confirm-message] {
      font-size: var(--ts-font-sm, 13px);
      color: var(--ts-text-primary, #e5e7eb);
      line-height: 1.5;
    }
    [data-ts-confirm-warning] {
      font-size: var(--ts-font-xs, 11px);
      color: var(--ts-color-bearish, #ef4444);
      font-weight: 600;
      padding: var(--ts-space-2, 8px);
      background: rgba(239, 68, 68, 0.1);
      border-radius: var(--ts-radius-sm, 6px);
      border: 1px solid rgba(239, 68, 68, 0.2);
    }
    [data-ts-confirm-actions] {
      display: flex;
      gap: var(--ts-space-2, 8px);
      justify-content: flex-end;
    }
    [data-ts-confirm-btn] {
      padding: 8px 16px;
      border-radius: var(--ts-radius-sm, 6px);
      font-size: var(--ts-font-sm, 13px);
      font-weight: 600;
      cursor: pointer;
      transition: opacity 120ms;
    }
    [data-ts-confirm-btn][data-variant="cancel"] {
      background: transparent;
      border: 1px solid var(--ts-panel-border, #374151);
      color: var(--ts-text-secondary, #9ca3af);
    }
    [data-ts-confirm-btn][data-variant="confirm"] {
      background: #f97316;
      border: none;
      color: #000;
      font-weight: 700;
    }
    [data-ts-confirm-btn]:hover {
      opacity: 0.85;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTradingModeStyles();
}

/* -------------------------------------------------------------------------- */
/*  Component                                                                 */
/* -------------------------------------------------------------------------- */

export const TradingModeToggle = forwardRef<HTMLDivElement, TradingModeToggleProps>(
  function TradingModeToggle({ mode, onModeChange, exchange }, ref) {
    const [showConfirm, setShowConfirm] = useState(false);

    const handleClick = useCallback(() => {
      if (mode === 'live') {
        // Switching from live to paper: no confirmation needed
        onModeChange('paper');
      } else {
        // Switching from paper to live: show confirmation
        setShowConfirm(true);
      }
    }, [mode, onModeChange]);

    const handleConfirm = useCallback(() => {
      setShowConfirm(false);
      onModeChange('live');
    }, [onModeChange]);

    const handleCancel = useCallback(() => {
      setShowConfirm(false);
    }, []);

    const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
      if (e.key === 'Escape') {
        setShowConfirm(false);
      }
    }, []);

    return (
      <>
        <div
          ref={ref}
          data-ts-trading-mode-toggle=""
          data-mode={mode}
          onClick={handleClick}
          onKeyDown={handleKeyDown}
          role="button"
          tabIndex={0}
          aria-label={`Trading mode: ${mode}. Click to switch.`}
        >
          <span data-ts-trading-mode-badge="" data-mode={mode}>
            {mode === 'paper' ? 'PAPER' : 'LIVE'}
          </span>
          {mode === 'paper' ? 'Simulated Trading' : 'Live Trading'}
        </div>

        {showConfirm && (
          <div data-ts-confirm-overlay="" onClick={handleCancel} onKeyDown={handleKeyDown} role="presentation">
            <div
              data-ts-confirm-dialog=""
              onClick={(e) => e.stopPropagation()}
              role="dialog"
              aria-modal="true"
              aria-labelledby="confirm-title"
            >
              <div data-ts-confirm-title="" id="confirm-title">
                Switch to Live Trading
              </div>
              <div data-ts-confirm-message="">
                You are switching to <strong>LIVE</strong> trading.
                Real orders will be placed on <strong>{exchange}</strong>.
              </div>
              <div data-ts-confirm-warning="">
                Real money is at risk. Orders will be submitted to the exchange immediately.
                Ensure your API credentials are configured correctly.
              </div>
              <div data-ts-confirm-actions="">
                <button
                  type="button"
                  data-ts-confirm-btn=""
                  data-variant="cancel"
                  onClick={handleCancel}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  data-ts-confirm-btn=""
                  data-variant="confirm"
                  onClick={handleConfirm}
                  autoFocus
                >
                  Switch to Live
                </button>
              </div>
            </div>
          </div>
        )}
      </>
    );
  },
);
