/**
 * Global app version gate. Runs synchronously on app load (before React).
 * If the stored app version doesn't match the current build version,
 * all localStorage is cleared to prevent stale state from breaking the UI.
 *
 * This is the first line of defense. Individual stores maintain their own
 * schema version checks as defense-in-depth.
 */

const APP_VERSION_KEY = 'deskmodal:app-version';

/**
 * Increment when ANY persisted state format changes across ANY app or store.
 * On mismatch all localStorage is wiped and the user starts fresh.
 */
const CURRENT_APP_VERSION = 2;

/**
 * Keys from older code versions that should always be removed,
 * regardless of whether the app version matches.
 */
const LEGACY_KEYS: readonly string[] = [
  'tradesurface.chart.session',
  'optiscript-scripts',
  'optiscript-debug-sidebar-width',
];

/**
 * Run the version gate synchronously. Must be called before any React
 * rendering, store hydration, or theme initialization.
 *
 * When a version mismatch is detected:
 * 1. All localStorage keys are removed
 * 2. The new version stamp is written
 * 3. A sessionStorage flag is set so the UI can show a brief notification
 *
 * Legacy keys are always cleaned up regardless of version match.
 */
export function checkAppVersion(): void {
  try {
    const stored = localStorage.getItem(APP_VERSION_KEY);
    const storedVersion = stored !== null ? parseInt(stored, 10) : NaN;

    if (storedVersion !== CURRENT_APP_VERSION) {
      localStorage.clear();
      localStorage.setItem(APP_VERSION_KEY, String(CURRENT_APP_VERSION));
      sessionStorage.setItem('deskmodal:state-reset', '1');
    } else {
      for (const key of LEGACY_KEYS) {
        localStorage.removeItem(key);
      }
    }
  } catch {
    // localStorage unavailable (e.g. sandboxed iframe) — continue with defaults
  }
}
