import type { CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  Skeleton                                                                  */
/*  Loading placeholder that matches component shape.                         */
/*  Uses --ts-skeleton-* tokens with shimmer animation.                       */
/* -------------------------------------------------------------------------- */

/* ----- Style injection for keyframes ------------------------------------- */

const SKELETON_STYLE_ID = 'ts-skeleton-styles';

function ensureSkeletonStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(SKELETON_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = SKELETON_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-skeleton-shimmer {
      0% { background-position: -200% 0; }
      100% { background-position: 200% 0; }
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-skeleton] {
        animation: none !important;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureSkeletonStyles();
}

/* ----- Props ------------------------------------------------------------- */

interface SkeletonProps {
  /** Width of the skeleton placeholder. Accepts CSS values. */
  width?: string | number;
  /** Height of the skeleton placeholder. Accepts CSS values. */
  height?: string | number;
  /** Border radius override. Defaults to --ts-skeleton-radius. */
  radius?: string | number;
  /** Render as a circle (forces equal width/height and 50% radius). */
  circle?: boolean;
  /** Additional inline styles. */
  style?: CSSProperties;
}

export function Skeleton({
  width = '100%',
  height = 16,
  radius,
  circle = false,
  style,
}: SkeletonProps): React.JSX.Element {
  const resolvedWidth = circle && typeof height === 'number' ? height : width;
  const resolvedRadius = circle
    ? '50%'
    : radius !== undefined
      ? radius
      : 'var(--ts-skeleton-radius)';

  const skeletonStyle: CSSProperties = {
    display: 'block',
    width: typeof resolvedWidth === 'number' ? `${resolvedWidth}px` : resolvedWidth,
    height: typeof height === 'number' ? `${height}px` : height,
    borderRadius: typeof resolvedRadius === 'number' ? `${resolvedRadius}px` : resolvedRadius,
    background: `linear-gradient(
      90deg,
      var(--ts-skeleton-bg) 0%,
      var(--ts-skeleton-shimmer) 40%,
      var(--ts-skeleton-bg) 80%
    )`,
    backgroundSize: '200% 100%',
    animation: 'ts-skeleton-shimmer 1.5s ease-in-out infinite',
    flexShrink: 0,
    ...style,
  };

  return (
    <div
      data-ts-skeleton=""
      role="status"
      aria-label="Loading"
      style={skeletonStyle}
    />
  );
}

Skeleton.displayName = 'Skeleton';
