import { useCallback, useEffect, forwardRef } from 'react';

interface KillSwitchProps {
  /** Whether the kill switch button is visible (only in live mode). */
  visible: boolean;
  /** Callback invoked when the kill switch is triggered. No confirmation. */
  onKill: () => void;
}

/* -------------------------------------------------------------------------- */
/*  Styles                                                                    */
/* -------------------------------------------------------------------------- */

const STYLE_ID = 'ts-kill-switch-styles';

function ensureKillSwitchStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-kill-switch] {
      display: flex;
      align-items: center;
      gap: var(--ts-space-1, 4px);
      padding: 4px 10px;
      background: rgba(239, 68, 68, 0.15);
      border: 2px solid var(--ts-color-bearish, #ef4444);
      border-radius: var(--ts-radius-sm, 6px);
      color: var(--ts-color-bearish, #ef4444);
      font-size: 10px;
      font-weight: 800;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      cursor: pointer;
      transition: all 100ms;
      line-height: 1;
    }
    [data-ts-kill-switch]:hover {
      background: var(--ts-color-bearish, #ef4444);
      color: #fff;
    }
    [data-ts-kill-switch]:active {
      transform: scale(0.97);
    }
    [data-ts-kill-switch-kbd] {
      font-size: 9px;
      opacity: 0.7;
      font-weight: 600;
    }
    @keyframes ts-kill-flash {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.5; }
    }
    [data-ts-kill-switch][data-activated] {
      animation: ts-kill-flash 200ms 3;
      background: var(--ts-color-bearish, #ef4444);
      color: #fff;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureKillSwitchStyles();
}

/* -------------------------------------------------------------------------- */
/*  Component                                                                 */
/* -------------------------------------------------------------------------- */

export const KillSwitch = forwardRef<HTMLButtonElement, KillSwitchProps>(
  function KillSwitch({ visible, onKill }, ref) {
    // Register global keyboard shortcut: Ctrl+Shift+X
    useEffect(() => {
      if (!visible) return;

      const handleKeyDown = (e: KeyboardEvent) => {
        if (e.ctrlKey && e.shiftKey && e.key === 'X') {
          e.preventDefault();
          e.stopPropagation();
          onKill();
        }
      };

      window.addEventListener('keydown', handleKeyDown, { capture: true });
      return () => {
        window.removeEventListener('keydown', handleKeyDown, { capture: true });
      };
    }, [visible, onKill]);

    const handleClick = useCallback(() => {
      onKill();
    }, [onKill]);

    if (!visible) return null;

    return (
      <button
        ref={ref}
        type="button"
        data-ts-kill-switch=""
        onClick={handleClick}
        title="Emergency cancel all open orders (Ctrl+Shift+X)"
        aria-label="Kill switch: cancel all open orders"
      >
        <KillIcon />
        KILL
        <span data-ts-kill-switch-kbd="">Ctrl+Shift+X</span>
      </button>
    );
  },
);

function KillIcon() {
  return (
    <svg width={12} height={12} viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
      <circle cx="8" cy="8" r="6.5" stroke="currentColor" strokeWidth="1.5" />
      <path d="M5 5l6 6M11 5l-6 6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  );
}
