import { forwardRef, type CSSProperties } from 'react';
import { IconButton } from '../primitives';
import { Calendar } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  DateRangeBar                                                              */
/*  Horizontal row of date range quick-access buttons for chart navigation.   */
/*  Uses --ts-selector-* tokens.                                              */
/* -------------------------------------------------------------------------- */

export interface DateRange {
  /** Display label (e.g., "1D", "5D", "1M", "YTD"). */
  label: string;
  /** Unique value. */
  value: string;
}

export interface DateRangeBarProps {
  /** Available date ranges. Defaults to standard set. */
  ranges?: DateRange[];
  /** Currently selected range value. */
  value?: string;
  /** Called when a range is selected. */
  onValueChange?: (value: string) => void;
  /** Called when "Go to date" is clicked. */
  onGoToDate?: () => void;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const DATE_RANGE_BAR_STYLE_ID = 'ts-date-range-bar-styles';

function ensureDateRangeBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DATE_RANGE_BAR_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DATE_RANGE_BAR_STYLE_ID;
  sheet.textContent = `
    [data-ts-date-range-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-date-range-button]:not(:disabled):not([data-active]):hover {
      color: var(--ts-selector-inactive-text-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDateRangeBarStyles();
}

/* ----- Default ranges ---------------------------------------------------- */

const DEFAULT_RANGES: DateRange[] = [
  { label: '1D', value: '1D' },
  { label: '5D', value: '5D' },
  { label: '1M', value: '1M' },
  { label: '3M', value: '3M' },
  { label: '6M', value: '6M' },
  { label: 'YTD', value: 'YTD' },
  { label: '1Y', value: '1Y' },
  { label: '5Y', value: '5Y' },
  { label: 'All', value: 'All' },
];

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '2px',
};

const buttonBaseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 'var(--ts-selector-height)',
  padding: `0 var(--ts-selector-padding-x)`,
  borderRadius: 'var(--ts-selector-radius)',
  fontSize: 'var(--ts-selector-font-size)',
  fontWeight: 'var(--ts-selector-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  userSelect: 'none',
  boxSizing: 'border-box',
  lineHeight: 1,
  transition: 'background 150ms, color 150ms',
};

function getButtonStyle(isActive: boolean): CSSProperties {
  return {
    ...buttonBaseStyle,
    background: isActive ? 'var(--ts-selector-active-bg)' : 'transparent',
    color: isActive ? 'var(--ts-selector-active-text)' : 'var(--ts-selector-inactive-text)',
  };
}

export const DateRangeBar = forwardRef<HTMLDivElement, DateRangeBarProps>(
  function DateRangeBar(
    {
      ranges = DEFAULT_RANGES,
      value,
      onValueChange,
      onGoToDate,
    },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-date-range-bar="" style={containerStyle}>
        {ranges.map((range) => {
          const isActive = range.value === value;
          return (
            <button
              key={range.value}
              type="button"
              data-ts-date-range-button=""
              {...(isActive ? { 'data-active': '' } : {})}
              style={getButtonStyle(isActive)}
              aria-pressed={isActive}
              onClick={() => onValueChange?.(range.value)}
            >
              {range.label}
            </button>
          );
        })}
        {onGoToDate !== undefined && (
          <IconButton
            icon={<Calendar size={14} />}
            label="Go to date"
            variant="ghost"
            size="sm"
            onClick={onGoToDate}
          />
        )}
      </div>
    );
  },
);

DateRangeBar.displayName = 'DateRangeBar';
