import { forwardRef, type CSSProperties } from 'react';
import { Toolbar } from '../primitives';
import { AggregationControl } from './AggregationControl';
import { OrderBookViewMode, type ViewMode } from './OrderBookViewMode';

/* -------------------------------------------------------------------------- */
/*  OrderBookHeader                                                            */
/*  Toolbar for order book: symbol label, aggregation control, view mode.      */
/*  Uses --ts-toolbar-* tokens.                                                */
/* -------------------------------------------------------------------------- */

export interface OrderBookHeaderProps {
  /** Instrument symbol (e.g., "BTCUSDT"). */
  symbol: string;
  /** Current aggregation tick size. */
  aggregation: number;
  /** Available tick sizes. */
  tickSizes: number[];
  /** Called when aggregation changes. */
  onAggregationChange: (tickSize: number) => void;
  /** Current view mode. */
  viewMode: ViewMode;
  /** Called when view mode changes. */
  onViewModeChange: (mode: ViewMode) => void;
  /** Price precision for display. */
  precision?: number;
}

/* ----- Styles ------------------------------------------------------------ */

const contentStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  width: '100%',
  gap: 'var(--ts-toolbar-item-gap)',
};

const symbolStyle: CSSProperties = {
  flex: '0 0 auto',
  fontSize: 'var(--ts-font-md)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-primary)',
  whiteSpace: 'nowrap',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
};

const spacerStyle: CSSProperties = {
  flex: '1 1 auto',
};

/* ----- Component --------------------------------------------------------- */

export const OrderBookHeader = forwardRef<HTMLDivElement, OrderBookHeaderProps>(
  function OrderBookHeader(
    {
      symbol,
      aggregation,
      tickSizes,
      onAggregationChange,
      viewMode,
      onViewModeChange,
      precision = 2,
    },
    ref,
  ) {
    return (
      <Toolbar ref={ref} orientation="horizontal">
        <div data-ts-ob-header="" style={contentStyle}>
          <span style={symbolStyle} data-testid="ob-header-symbol">
            {symbol}
          </span>
          <div style={spacerStyle} />
          <AggregationControl
            value={aggregation}
            tickSizes={tickSizes}
            onValueChange={onAggregationChange}
            precision={precision}
          />
          <OrderBookViewMode
            value={viewMode}
            onValueChange={onViewModeChange}
          />
        </div>
      </Toolbar>
    );
  },
);

OrderBookHeader.displayName = 'OrderBookHeader';
