import { useEffect, useRef, type CSSProperties } from 'react';
import { formatPrice } from './format-number';

/* -------------------------------------------------------------------------- */
/*  PriceDisplay                                                              */
/*  Formatted price with direction coloring and flash animation.              */
/*  Uses --ts-price-* tokens.                                                 */
/* -------------------------------------------------------------------------- */

type PriceSize = 'sm' | 'md' | 'lg';

export interface PriceDisplayProps {
  /** Current price value. */
  value: number;
  /** Previous price value for direction comparison. */
  previousValue?: number;
  /** Decimal places to display. */
  precision?: number;
  /** Display size variant. */
  size?: PriceSize;
  /** Whether to show background flash on value change. */
  showFlash?: boolean;
}

/* ----- Style injection for flash animation ------------------------------- */

const FLASH_STYLE_ID = 'ts-price-flash-styles';

function ensureFlashStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(FLASH_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = FLASH_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-price-flash-up {
      0% { background-color: var(--ts-price-flash-up-bg); }
      100% { background-color: transparent; }
    }
    @keyframes ts-price-flash-down {
      0% { background-color: var(--ts-price-flash-down-bg); }
      100% { background-color: transparent; }
    }
    [data-ts-price-flash="up"] {
      animation: ts-price-flash-up var(--ts-price-flash-duration, 600ms) ease-out;
    }
    [data-ts-price-flash="down"] {
      animation: ts-price-flash-down var(--ts-price-flash-duration, 600ms) ease-out;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureFlashStyles();
}

/* ----- Size map ---------------------------------------------------------- */

const SIZE_FONT: Record<PriceSize, string> = {
  sm: 'var(--ts-font-sm)',
  md: 'var(--ts-font-md)',
  lg: 'var(--ts-font-lg)',
};

/* ----- Direction helpers ------------------------------------------------- */

type Direction = 'up' | 'down' | 'neutral';

function getDirection(value: number, previousValue: number | undefined): Direction {
  if (previousValue === undefined) return 'neutral';
  if (value > previousValue) return 'up';
  if (value < previousValue) return 'down';
  return 'neutral';
}

const DIRECTION_COLOR: Record<Direction, string> = {
  up: 'var(--ts-price-up-text)',
  down: 'var(--ts-price-down-text)',
  neutral: 'var(--ts-price-neutral-text)',
};

/* ----- Component --------------------------------------------------------- */

export function PriceDisplay({
  value,
  previousValue,
  precision = 2,
  size = 'md',
  showFlash = true,
}: PriceDisplayProps): React.JSX.Element {
  const spanRef = useRef<HTMLSpanElement>(null);
  const prevValueRef = useRef<number>(value);

  const direction = getDirection(value, previousValue);

  useEffect(() => {
    if (!showFlash) return;
    if (prevValueRef.current === value) return;

    const el = spanRef.current;
    if (!el) return;

    const flashDirection = value > prevValueRef.current ? 'up' : 'down';
    el.removeAttribute('data-ts-price-flash');
    // Force reflow to restart animation
    void el.offsetWidth;
    el.setAttribute('data-ts-price-flash', flashDirection);

    const handleEnd = (): void => {
      el.removeAttribute('data-ts-price-flash');
    };
    el.addEventListener('animationend', handleEnd, { once: true });

    prevValueRef.current = value;

    return () => {
      el.removeEventListener('animationend', handleEnd);
    };
  }, [value, showFlash]);

  const style: CSSProperties = {
    display: 'inline-block',
    fontFamily: 'var(--ts-price-font)',
    fontSize: SIZE_FONT[size],
    fontWeight: 'var(--ts-price-font-weight)' as unknown as number,
    color: DIRECTION_COLOR[direction],
    fontVariantNumeric: 'tabular-nums',
    lineHeight: 1.4,
    padding: '0 2px',
    borderRadius: 'var(--ts-radius-sm)',
  };

  return (
    <span
      ref={spanRef}
      className="ts-data-value"
      style={style}
      data-direction={direction}
      data-testid="price-display"
    >
      {formatPrice(value, precision)}
    </span>
  );
}

PriceDisplay.displayName = 'PriceDisplay';
