import { useState, useCallback } from "react";
import type { Context, IntentResolution } from "../fdc3-types";
import { useFdc3 } from "./use-fdc3";

/** Return type for the useRaiseIntent hook. */
export interface UseRaiseIntentResult {
  /** Raise an intent with a context, optionally targeting a specific app. */
  raiseIntent: (
    intent: string,
    context: Context,
    app?: string
  ) => Promise<IntentResolution>;
  /** Whether an intent is currently being resolved. */
  pending: boolean;
  /** The most recent error from raising an intent, or null. */
  error: Error | null;
}

/**
 * Hook providing intent raising capability with loading and error state.
 *
 * Usage:
 *   const { raiseIntent, pending, error } = useRaiseIntent();
 *   await raiseIntent("deskmodal.ViewDepth", instrumentContext);
 */
export function useRaiseIntent(): UseRaiseIntentResult {
  const fdc3 = useFdc3();
  const [pending, setPending] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const raiseIntent = useCallback(
    async (
      intent: string,
      context: Context,
      app?: string
    ): Promise<IntentResolution> => {
      if (!fdc3) {
        const noAgentError = new Error(
          "FDC3 Desktop Agent is not available. Cannot raise intent."
        );
        setError(noAgentError);
        return Promise.reject(noAgentError);
      }

      setPending(true);
      setError(null);

      try {
        const resolution = await fdc3.raiseIntent(intent, context, app);
        setPending(false);
        return resolution;
      } catch (err) {
        const intentError =
          err instanceof Error
            ? err
            : new Error(`Failed to raise intent "${intent}"`);
        setError(intentError);
        setPending(false);
        throw intentError;
      }
    },
    [fdc3]
  );

  return { raiseIntent, pending, error };
}
