import { forwardRef, useState, useMemo, useCallback, type CSSProperties } from 'react';
import { ChevronDown } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  TimezoneSelector                                                          */
/*  Dropdown selector for chart timezone with optional current time display.  */
/*  Uses --ts-selector-* and --ts-overlay-* tokens.                           */
/* -------------------------------------------------------------------------- */

export interface TimezoneOption {
  /** IANA timezone identifier (e.g., "UTC", "America/New_York"). */
  value: string;
  /** Display label (e.g., "UTC", "New York (EST)"). */
  label: string;
  /** GMT offset string for display (e.g., "GMT+0", "GMT-5"). */
  offset: string;
}

export interface TimezoneSelectorProps {
  /** Available timezone options. */
  options: TimezoneOption[];
  /** Currently selected timezone value. */
  value: string;
  /** Called when a timezone is selected. */
  onValueChange: (value: string) => void;
  /** Current time display string (e.g., "04:22:17 UTC"). */
  currentTime?: string;
  /** Whether to show the current time. Default true. */
  showTime?: boolean;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const TZ_SELECTOR_STYLE_ID = 'ts-timezone-selector-styles';

function ensureTimezoneSelectorStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TZ_SELECTOR_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TZ_SELECTOR_STYLE_ID;
  sheet.textContent = `
    [data-ts-timezone-selector-trigger]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-timezone-selector-trigger]:hover {
      color: var(--ts-selector-inactive-text-hover);
    }
    [data-ts-timezone-option]:hover {
      background: var(--ts-select-item-bg-hover);
    }
    [data-ts-timezone-option]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-timezone-option][data-selected] {
      background: var(--ts-select-item-bg-selected);
      color: var(--ts-select-item-text-selected);
    }
    [data-ts-timezone-search]:focus-visible {
      outline: none;
      border-color: var(--ts-input-border-focus);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTimezoneSelectorStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  gap: '4px',
  height: 'var(--ts-selector-height)',
  padding: `0 var(--ts-selector-padding-x)`,
  fontSize: 'var(--ts-selector-font-size)',
  fontFamily: 'inherit',
  color: 'var(--ts-selector-inactive-text)',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  userSelect: 'none',
  borderRadius: 'var(--ts-selector-radius)',
  transition: 'color 150ms',
  boxSizing: 'border-box',
};

const dropdownStyle: CSSProperties = {
  position: 'absolute',
  bottom: '100%',
  right: 0,
  width: 220,
  maxHeight: 280,
  background: 'var(--ts-overlay-bg)',
  border: '1px solid var(--ts-overlay-border)',
  borderRadius: 'var(--ts-overlay-radius)',
  boxShadow: 'var(--ts-overlay-shadow)',
  overflow: 'hidden',
  zIndex: 100,
  display: 'flex',
  flexDirection: 'column',
};

const searchInputStyle: CSSProperties = {
  all: 'unset',
  width: '100%',
  height: 32,
  padding: `0 var(--ts-space-2)`,
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'inherit',
  color: 'var(--ts-input-text)',
  background: 'var(--ts-input-bg)',
  borderBottom: '1px solid var(--ts-overlay-border)',
  boxSizing: 'border-box',
};

const listStyle: CSSProperties = {
  overflow: 'auto',
  flex: '1 1 auto',
  padding: 'var(--ts-space-1) 0',
};

const optionStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  height: 'var(--ts-select-item-height)',
  padding: `0 var(--ts-select-item-padding-x)`,
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'inherit',
  color: 'var(--ts-select-item-text)',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  border: 'none',
  background: 'transparent',
  width: '100%',
  boxSizing: 'border-box',
  textAlign: 'left',
};

const offsetLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  marginLeft: 'var(--ts-space-2)',
};

export const TimezoneSelector = forwardRef<HTMLDivElement, TimezoneSelectorProps>(
  function TimezoneSelector(
    {
      options,
      value,
      onValueChange,
      currentTime,
      showTime = true,
    },
    ref,
  ) {
    const [open, setOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');

    const selectedOption = useMemo(
      () => options.find((opt) => opt.value === value),
      [options, value],
    );

    const filteredOptions = useMemo(() => {
      if (searchQuery.length === 0) return options;
      const lower = searchQuery.toLowerCase();
      return options.filter(
        (opt) =>
          opt.label.toLowerCase().includes(lower) ||
          opt.value.toLowerCase().includes(lower) ||
          opt.offset.toLowerCase().includes(lower),
      );
    }, [options, searchQuery]);

    const handleToggle = useCallback(() => {
      setOpen((prev) => {
        if (!prev) setSearchQuery('');
        return !prev;
      });
    }, []);

    const handleSelect = useCallback(
      (optionValue: string) => {
        onValueChange(optionValue);
        setOpen(false);
        setSearchQuery('');
      },
      [onValueChange],
    );

    const triggerLabel = showTime && currentTime
      ? currentTime
      : selectedOption?.label ?? value;

    return (
      <div ref={ref} data-ts-timezone-selector="" style={{ position: 'relative', display: 'inline-flex' }}>
        <button
          type="button"
          data-ts-timezone-selector-trigger=""
          style={triggerStyle}
          onClick={handleToggle}
          aria-haspopup="listbox"
          aria-expanded={open}
          aria-label="Select timezone"
        >
          <span>{triggerLabel}</span>
          <ChevronDown size={12} aria-hidden />
        </button>

        {open && (
          <div style={dropdownStyle} role="listbox" aria-label="Timezone options">
            <input
              data-ts-timezone-search=""
              type="text"
              style={searchInputStyle}
              placeholder="Search timezone..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              autoFocus
              aria-label="Search timezones"
            />
            <div style={listStyle}>
              {filteredOptions.map((opt) => {
                const isSelected = opt.value === value;
                return (
                  <button
                    key={opt.value}
                    type="button"
                    role="option"
                    data-ts-timezone-option=""
                    {...(isSelected ? { 'data-selected': '' } : {})}
                    aria-selected={isSelected}
                    style={optionStyle}
                    onClick={() => handleSelect(opt.value)}
                  >
                    <span>{opt.label}</span>
                    <span style={offsetLabelStyle}>{opt.offset}</span>
                  </button>
                );
              })}
            </div>
          </div>
        )}
      </div>
    );
  },
);

TimezoneSelector.displayName = 'TimezoneSelector';
