import { useMemo, type CSSProperties } from 'react';
import { type ColumnDef } from '@tanstack/react-table';
import { DataGrid } from '../../primitives';
import { ScreenerCellRenderer, type CellType } from './ScreenerCellRenderer';

/* -------------------------------------------------------------------------- */
/*  ScreenerTable                                                             */
/*  Crypto screener table wrapping DataGrid with ScreenerCellRenderer.        */
/*  Composes DataGrid + ScreenerCellRenderer. Uses --ts-screener-* tokens.    */
/* -------------------------------------------------------------------------- */

export interface ScreenerColumnDef {
  /** Unique column key. */
  key: string;
  /** Display header label. */
  header: string;
  /** Optional sub-label (e.g., "24h" under "Volume"). */
  subHeader?: string;
  /** Cell type for the ScreenerCellRenderer. */
  cellType: CellType;
  /** Field path in the data row to read the value from. */
  field: string;
  /** Secondary field for previous value comparison (price cells). */
  previousField?: string;
  /** Sparkline data field (for sparkline cells). */
  sparklineField?: string;
  /** Default width in pixels. */
  width?: number;
  /** Text alignment. */
  align?: 'left' | 'center' | 'right';
  /** Whether this column is sortable. */
  sortable?: boolean;
  /** Precision for price formatting. */
  precision?: number;
}

export interface ScreenerTableProps<TData extends Record<string, unknown> & { id: string }> {
  /** Column definitions. */
  columns: ScreenerColumnDef[];
  /** Data rows. */
  data: TData[];
  /** Called when a row is clicked. */
  onRowClick?: (row: TData) => void;
  /** ID of the currently selected row. */
  selectedRowId?: string;
  /** Row height in pixels. */
  rowHeight?: number;
  /** Whether to show the search icon in the first column header. */
  showSearch?: boolean;
  /** Called when search is triggered. */
  onSearchClick?: () => void;
  /** Total result count to show in the first column sub-header. */
  resultCount?: number;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-screener-table-styles';

function ensureScreenerTableStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-screener-table] [data-ts-datagrid-header] {
      background: var(--ts-data-header-bg);
    }
    [data-ts-screener-table] [data-ts-datagrid-row]:hover {
      background: var(--ts-data-row-bg-hover) !important;
    }
    [data-ts-screener-sub-header] {
      font-size: var(--ts-font-xs);
      color: var(--ts-text-tertiary);
      font-weight: normal;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureScreenerTableStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  flex: 1,
  overflow: 'hidden',
};

const headerContentStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 0,
};

/* ----- Helpers ----------------------------------------------------------- */

function getNestedValue(obj: Record<string, unknown>, path: string): unknown {
  const parts = path.split('.');
  let current: unknown = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = (current as Record<string, unknown>)[part];
  }
  return current;
}

/* ----- Component --------------------------------------------------------- */

export function ScreenerTable<TData extends Record<string, unknown> & { id: string }>({
  columns,
  data,
  onRowClick,
  selectedRowId,
  rowHeight = 36,
  resultCount,
}: ScreenerTableProps<TData>): React.JSX.Element {
  const tanstackColumns = useMemo((): ColumnDef<TData, unknown>[] => {
    return columns.map((col, idx) => ({
      id: col.key,
      accessorFn: (row: TData) => getNestedValue(row, col.field),
      size: col.width ?? 120,
      enableSorting: col.sortable ?? true,
      header: () => (
        <div style={headerContentStyle}>
          <span>
            {col.header}
            {idx === 0 && resultCount !== undefined && (
              <span data-ts-screener-sub-header="" style={{ marginLeft: 8 }}>
                {resultCount.toLocaleString()}
              </span>
            )}
          </span>
          {col.subHeader !== undefined && (
            <span data-ts-screener-sub-header="">{col.subHeader}</span>
          )}
        </div>
      ),
      cell: ({ row }) => {
        const rowData = row.original;
        const cellValue = getNestedValue(rowData, col.field);
        const previousValue = col.previousField !== undefined
          ? getNestedValue(rowData, col.previousField) as number | undefined
          : undefined;
        const sparklineData = col.sparklineField !== undefined
          ? getNestedValue(rowData, col.sparklineField) as number[] | undefined
          : undefined;

        return (
          <ScreenerCellRenderer
            type={col.cellType}
            value={cellValue}
            previousValue={previousValue}
            sparklineData={sparklineData}
            precision={col.precision}
          />
        );
      },
    }));
  }, [columns, resultCount]);

  return (
    <div data-ts-screener-table="" style={rootStyle}>
      <DataGrid
        columns={tanstackColumns}
        data={data}
        onRowClick={onRowClick}
        selectedRowId={selectedRowId}
        sortable={true}
        virtualizeRows={true}
        rowHeight={rowHeight}
      />
    </div>
  );
}

ScreenerTable.displayName = 'ScreenerTable';
