import { type CSSProperties } from 'react';
import { DropdownMenu, IconButton } from '../../primitives';
import { Download, FileText, Clipboard, Loader2 } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ScreenerExport                                                            */
/*  Export dropdown with CSV and clipboard options.                            */
/*  Composes DropdownMenu + IconButton. Uses --ts-screener-* tokens.          */
/* -------------------------------------------------------------------------- */

export interface ScreenerExportProps {
  /** Called when CSV export is triggered. */
  onExportCsv: () => void;
  /** Called when clipboard copy is triggered. */
  onCopyToClipboard: () => void;
  /** Whether export is in progress. */
  exporting?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-screener-export-styles';

function ensureScreenerExportStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    @keyframes ts-screener-export-spin {
      from { transform: rotate(0deg); }
      to { transform: rotate(360deg); }
    }
    [data-ts-screener-export-spinner] {
      animation: ts-screener-export-spin 1s linear infinite;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureScreenerExportStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const spinnerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
};

/* ----- Component --------------------------------------------------------- */

export function ScreenerExport({
  onExportCsv,
  onCopyToClipboard,
  exporting = false,
}: ScreenerExportProps): React.JSX.Element {
  const triggerIcon = exporting ? (
    <span data-ts-screener-export-spinner="" style={spinnerStyle}>
      <Loader2 size={16} aria-hidden />
    </span>
  ) : (
    <Download size={16} />
  );

  return (
    <div data-ts-screener-export="">
      <DropdownMenu>
        <DropdownMenu.Trigger>
          <IconButton
            icon={triggerIcon}
            label={exporting ? 'Exporting...' : 'Export data'}
            variant="ghost"
            size="sm"
            disabled={exporting}
          />
        </DropdownMenu.Trigger>
        <DropdownMenu.Content align="end">
          <DropdownMenu.Item
            icon={<FileText size={14} />}
            onSelect={onExportCsv}
          >
            Export CSV
          </DropdownMenu.Item>
          <DropdownMenu.Item
            icon={<Clipboard size={14} />}
            onSelect={onCopyToClipboard}
          >
            Copy to clipboard
          </DropdownMenu.Item>
        </DropdownMenu.Content>
      </DropdownMenu>
    </div>
  );
}

ScreenerExport.displayName = 'ScreenerExport';
