import { useCallback, useState, useRef, type CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  SizeInput — compact quantity field with increment buttons                 */
/* -------------------------------------------------------------------------- */

interface SizeInputProps {
  value: number;
  onChange: (value: number) => void;
}

const SIZE_INCREMENTS = [0.2, 0.5, 1, 5, 10, 20, 100];

const inputStyle: CSSProperties = {
  width: '100%',
  padding: '6px 8px',
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  border: '1px solid var(--ts-panel-border, #374151)',
  borderRadius: '3px',
  color: 'var(--ts-text-primary, #e5e7eb)',
  fontSize: '12px',
  fontWeight: 600,
  fontFamily: 'var(--ts-watchlist-price-font, monospace)',
  outline: 'none',
  boxSizing: 'border-box',
};

const gridStyle: CSSProperties = {
  display: 'flex',
  gap: '3px',
  marginTop: '4px',
};

const incrementBtnStyle: CSSProperties = {
  flex: '1 1 auto',
  minWidth: 0,
  padding: '3px 2px',
  background: 'transparent',
  border: '1px solid var(--ts-accent-default, #3b82f6)',
  borderRadius: '3px',
  color: 'var(--ts-accent-default, #3b82f6)',
  fontSize: '10px',
  fontWeight: 600,
  fontFamily: 'var(--ts-watchlist-price-font, monospace)',
  cursor: 'pointer',
  transition: 'background 80ms, color 80ms',
  whiteSpace: 'nowrap',
};

export function SizeInput({ value, onChange }: SizeInputProps) {
  // Track raw text while editing to allow intermediate states like "0." or "1.5"
  const [rawText, setRawText] = useState<string | null>(null);
  const isEditing = useRef(false);

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const raw = e.target.value.replace(/[^0-9.]/g, '');
      // Allow at most one decimal point
      const parts = raw.split('.');
      const sanitized = parts.length > 2 ? parts[0] + '.' + parts.slice(1).join('') : raw;
      setRawText(sanitized);
      // Parse and propagate, but don't clear intermediate states like "0."
      const parsed = parseFloat(sanitized);
      if (!isNaN(parsed)) {
        onChange(parsed);
      } else if (sanitized === '' || sanitized === '.') {
        onChange(0);
      }
    },
    [onChange],
  );

  const handleFocus = useCallback(() => {
    isEditing.current = true;
    // Show current value as editable text
    setRawText(value === 0 ? '' : value.toString());
  }, [value]);

  const handleBlur = useCallback(() => {
    isEditing.current = false;
    setRawText(null); // Revert to formatted display
  }, []);

  const handleIncrement = useCallback(
    (increment: number) => {
      const newVal = Math.max(0, parseFloat((value + increment).toFixed(8)));
      onChange(newVal);
      setRawText(null);
    },
    [value, onChange],
  );

  const displayValue = (): string => {
    if (rawText !== null) return rawText;
    if (value === 0) return '';
    if (Number.isInteger(value)) return value.toLocaleString();
    return value.toString();
  };

  return (
    <div>
      <input
        type="text"
        inputMode="decimal"
        value={displayValue()}
        onChange={handleChange}
        onFocus={handleFocus}
        onBlur={handleBlur}
        placeholder="0"
        style={inputStyle}
        aria-label="Order size"
      />
      <div style={gridStyle}>
        {SIZE_INCREMENTS.map((inc) => (
          <button
            key={inc}
            type="button"
            style={incrementBtnStyle}
            onClick={() => handleIncrement(inc)}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = 'var(--ts-accent-default, #3b82f6)';
              e.currentTarget.style.color = '#fff';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = 'transparent';
              e.currentTarget.style.color = 'var(--ts-accent-default, #3b82f6)';
            }}
          >
            +{inc}
          </button>
        ))}
      </div>
    </div>
  );
}
