import { useEffect } from 'react';

const STATE_RESET_KEY = 'deskmodal:state-reset';

/**
 * Shows a brief info toast when the version gate has cleared persisted state.
 * Reads the `deskmodal:state-reset` flag from sessionStorage (set by the
 * version gate) and fires a toast via the provided callback. The flag is
 * consumed immediately so the notification only appears once per session.
 *
 * @param showToast - Callback to display the notification. Receives the
 *   message string. This avoids a hard dependency on any specific toast lib.
 */
export function useStateResetNotification(showToast: (message: string) => void): void {
  useEffect(() => {
    try {
      if (sessionStorage.getItem(STATE_RESET_KEY) === '1') {
        sessionStorage.removeItem(STATE_RESET_KEY);
        showToast('Settings reset \u2014 app updated');
      }
    } catch {
      // sessionStorage unavailable — silently skip
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps
}
