import { useCallback, useState, type CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  PriceInput — compact numeric price field with +/- stepper buttons         */
/* -------------------------------------------------------------------------- */

interface PriceInputProps {
  value: number;
  onChange: (value: number) => void;
  step: number;
  label?: string;
}

const wrapStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  border: '1px solid var(--ts-panel-border, #374151)',
  borderRadius: '3px',
  overflow: 'hidden',
};

const inputStyle: CSSProperties = {
  flex: 1,
  padding: '6px 8px',
  background: 'transparent',
  border: 'none',
  color: 'var(--ts-text-primary, #e5e7eb)',
  fontSize: '12px',
  fontWeight: 600,
  fontFamily: 'var(--ts-watchlist-price-font, monospace)',
  outline: 'none',
  minWidth: 0,
};

const stepBtnStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: '26px',
  padding: '6px 0',
  background: 'transparent',
  border: 'none',
  borderLeft: '1px solid var(--ts-panel-border, #374151)',
  color: 'var(--ts-text-secondary, #9ca3af)',
  cursor: 'pointer',
  fontSize: '13px',
  lineHeight: 1,
};

export function PriceInput({ value, onChange, step, label }: PriceInputProps) {
  const precision = step < 0.01 ? 6 : step < 1 ? 4 : 2;
  const [rawText, setRawText] = useState<string | null>(null);

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const raw = e.target.value.replace(/[^0-9.]/g, '');
      const parts = raw.split('.');
      const sanitized = parts.length > 2 ? parts[0] + '.' + parts.slice(1).join('') : raw;
      setRawText(sanitized);
      const parsed = parseFloat(sanitized);
      if (!isNaN(parsed)) {
        onChange(parsed);
      } else if (sanitized === '' || sanitized === '.') {
        onChange(0);
      }
    },
    [onChange],
  );

  const handleFocus = useCallback(() => {
    setRawText(value > 0 ? value.toFixed(precision) : '');
  }, [value, precision]);

  const handleBlur = useCallback(() => {
    setRawText(null);
  }, []);

  const handleStep = useCallback(
    (dir: 1 | -1) => {
      onChange(parseFloat((value + step * dir).toFixed(precision)));
      setRawText(null);
    },
    [value, step, precision, onChange],
  );

  const displayValue = rawText !== null ? rawText : (value > 0 ? value.toFixed(precision) : '');

  return (
    <div style={wrapStyle}>
      <input
        type="text"
        inputMode="decimal"
        value={displayValue}
        onChange={handleChange}
        onFocus={handleFocus}
        onBlur={handleBlur}
        placeholder={label ?? '0.00'}
        style={inputStyle}
        aria-label={label ?? 'Price'}
      />
      <button type="button" style={stepBtnStyle} onClick={() => handleStep(-1)} tabIndex={-1}>−</button>
      <button type="button" style={stepBtnStyle} onClick={() => handleStep(1)} tabIndex={-1}>+</button>
    </div>
  );
}
