import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { Toolbar } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  BottomBar                                                                 */
/*  Horizontal toolbar at the bottom of the chart area.                       */
/*  Uses --ts-toolbar-* tokens. Three sections: left, center, right.          */
/* -------------------------------------------------------------------------- */

export interface BottomBarProps {
  /** Content for the date range section (left). */
  dateRangeContent?: ReactNode;
  /** Content for the center section (chart info, etc.). */
  centerContent?: ReactNode;
  /** Content for the right section (timezone, adjustments). */
  rightContent?: ReactNode;
  /** Whether to hide the bottom bar (pane mode). */
  hidden?: boolean;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const BOTTOM_BAR_STYLE_ID = 'ts-bottom-bar-styles';

function ensureBottomBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(BOTTOM_BAR_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = BOTTOM_BAR_STYLE_ID;
  sheet.textContent = `
    [data-ts-bottom-bar]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureBottomBarStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const sectionStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-toolbar-item-gap)',
};

const leftSectionStyle: CSSProperties = {
  ...sectionStyle,
  flex: '0 0 auto',
};

const centerSectionStyle: CSSProperties = {
  ...sectionStyle,
  flex: '1 1 auto',
  justifyContent: 'center',
};

const rightSectionStyle: CSSProperties = {
  ...sectionStyle,
  flex: '0 0 auto',
  marginLeft: 'auto',
};

export const BottomBar = forwardRef<HTMLDivElement, BottomBarProps>(
  function BottomBar(
    { dateRangeContent, centerContent, rightContent, hidden = false },
    ref,
  ) {
    if (hidden) return null;

    const hasLeft = dateRangeContent !== undefined;
    const hasCenter = centerContent !== undefined;
    const hasRight = rightContent !== undefined;

    return (
      <Toolbar
        ref={ref}
        orientation="horizontal"
      >
        <div
          data-ts-bottom-bar=""
          style={{
            display: 'flex',
            alignItems: 'center',
            width: '100%',
            borderTop: '1px solid var(--ts-toolbar-border)',
            borderBottom: 'none',
          }}
        >
          {hasLeft && <div style={leftSectionStyle}>{dateRangeContent}</div>}
          {hasCenter && <div style={centerSectionStyle}>{centerContent}</div>}
          {!hasCenter && <div style={{ flex: '1 1 auto' }} />}
          {hasRight && <div style={rightSectionStyle}>{rightContent}</div>}
        </div>
      </Toolbar>
    );
  },
);

BottomBar.displayName = 'BottomBar';
