import { forwardRef, type CSSProperties, type ReactNode } from 'react';

/* -------------------------------------------------------------------------- */
/*  AppShell                                                                  */
/*  Outermost inner container for all Deskmodal Desk apps.                 */
/*  Establishes CSS container query context for pane/window adaptation.       */
/*  Does NOT render window chrome — Desk provides that.                       */
/*  Uses --ts-app-shell-* tokens.                                             */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-app-shell-styles';

function ensureAppShellStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    @container ts-app (max-width: 600px) {
      [data-ts-app-shell-content] {
        padding: var(--ts-app-shell-content-padding-compact);
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAppShellStyles();
}

/* ----- Types ------------------------------------------------------------- */

export type AppShellDensity = 'compact' | 'default' | 'comfortable';

export interface AppShellProps {
  /** App content. */
  children: ReactNode;
  /** Optional header content (rendered via AppHeader). */
  header?: ReactNode;
  /** Optional footer/dock content (e.g., ConnectionStatusBar). */
  footer?: ReactNode;
  /** Density mode override. If omitted, reads from Desk CSS token. */
  density?: AppShellDensity;
  /** Additional CSS class name. */
  className?: string;
  /** When true, content fills available space with no padding or scrolling. Use for canvas-based apps like charts. */
  fillContent?: boolean;
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  width: '100%',
  height: '100%',
  background: 'var(--ts-app-shell-bg)',
  containerType: 'inline-size',
  containerName: 'ts-app',
  overflow: 'hidden',
  boxSizing: 'border-box',
};

const headerSlotStyle: CSSProperties = {
  flexShrink: 0,
};

const contentStyle: CSSProperties = {
  flex: 1,
  minHeight: 0,
  overflowY: 'auto',
  padding: 'var(--ts-app-shell-content-padding)',
  boxSizing: 'border-box',
};

const fillContentStyle: CSSProperties = {
  flex: 1,
  minHeight: 0,
  overflow: 'hidden',
  padding: 0,
  boxSizing: 'border-box',
};

const footerSlotStyle: CSSProperties = {
  flexShrink: 0,
};

/* ----- Component --------------------------------------------------------- */

export const AppShell = forwardRef<HTMLDivElement, AppShellProps>(
  function AppShell({ children, header, footer, density, className, fillContent }, ref) {
    return (
      <div
        ref={ref}
        data-ts-app-shell=""
        data-density={density}
        className={className}
        style={rootStyle}
      >
        {header !== undefined && header !== null ? (
          <div data-ts-app-shell-header="" style={headerSlotStyle}>
            {header}
          </div>
        ) : null}
        <main data-ts-app-shell-content="" style={fillContent ? fillContentStyle : contentStyle}>
          {children}
        </main>
        {footer !== undefined && footer !== null ? (
          <div data-ts-app-shell-footer="" style={footerSlotStyle}>
            {footer}
          </div>
        ) : null}
      </div>
    );
  },
);

AppShell.displayName = 'AppShell';
