import { useState, useCallback, forwardRef, type CSSProperties, type ReactNode } from 'react';
import { Toolbar, IconButton, Tooltip } from '../primitives';
import { ToolCategory, type ToolConfig } from './ToolCategory';
import { ToolFlyout } from './ToolFlyout';

/* -------------------------------------------------------------------------- */
/*  LeftToolbar                                                               */
/*  Vertical toolbar on the left side of the chart containing tool categories */
/*  with flyouts and drawing mode controls.                                   */
/*  Uses Toolbar primitive (vertical) with --ts-toolbar-* tokens.             */
/* -------------------------------------------------------------------------- */

export interface ToolCategoryConfig {
  /** Category label (e.g., "Cursors", "Trend tools"). */
  label: string;
  /** Currently selected tool in this category (shown as primary button). */
  activeTool: ToolConfig;
  /** All tools in this category (shown in flyout). */
  tools: ToolConfig[];
}

export interface LeftToolbarProps {
  /** Tool categories to render. */
  categories: ToolCategoryConfig[];
  /** Currently active tool value. */
  activeToolValue?: string;
  /** Called when a tool is selected from any category. */
  onToolSelect: (toolValue: string) => void;
  /** Whether magnet mode is enabled. */
  magnetEnabled?: boolean;
  /** Called when magnet mode is toggled. */
  onMagnetToggle?: (enabled: boolean) => void;
  /** Whether "stay in drawing mode" is enabled. */
  stayInDrawingMode?: boolean;
  /** Called when stay-in-drawing-mode is toggled. */
  onStayInDrawingModeToggle?: (enabled: boolean) => void;
  /** Whether all drawings are locked. */
  drawingsLocked?: boolean;
  /** Called when lock-drawings is toggled. */
  onLockDrawingsToggle?: (locked: boolean) => void;
  /** Called when "remove all drawings" is triggered. */
  onRemoveAllDrawings?: () => void;
  /** Whether to use compact mode. In compact mode, only icons are shown. */
  compact?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-left-toolbar-styles';

function ensureLeftToolbarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-left-toolbar] {
      flex-shrink: 0;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureLeftToolbarStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const wrapperStyle: CSSProperties = {
  display: 'contents',
};

/* ----- Component --------------------------------------------------------- */

export const LeftToolbar = forwardRef<HTMLDivElement, LeftToolbarProps>(
  function LeftToolbar(
    {
      categories,
      activeToolValue,
      onToolSelect,
      magnetEnabled = false,
      onMagnetToggle,
      stayInDrawingMode = false,
      onStayInDrawingModeToggle,
      drawingsLocked = false,
      onLockDrawingsToggle,
      onRemoveAllDrawings,
    },
    ref,
  ) {
    const [openFlyout, setOpenFlyout] = useState<string | null>(null);

    const handleFlyoutOpen = useCallback((label: string) => {
      setOpenFlyout((prev) => (prev === label ? null : label));
    }, []);

    const handleFlyoutOpenChange = useCallback((label: string, open: boolean) => {
      if (!open) {
        setOpenFlyout((prev) => (prev === label ? null : prev));
      }
    }, []);

    const handleToolSelect = useCallback(
      (toolValue: string) => {
        onToolSelect(toolValue);
        setOpenFlyout(null);
      },
      [onToolSelect],
    );

    const isCategoryActive = (cat: ToolCategoryConfig): boolean => {
      if (activeToolValue === undefined) return false;
      return cat.tools.some((t) => t.value === activeToolValue);
    };

    return (
      <Toolbar ref={ref} orientation="vertical">
        <div data-ts-left-toolbar="" style={wrapperStyle}>
          {/* Tool categories */}
          <Toolbar.Group>
            {categories.map((cat) => (
              <ToolFlyout
                key={cat.label}
                tools={cat.tools}
                selectedValue={activeToolValue}
                onToolSelect={handleToolSelect}
                open={openFlyout === cat.label}
                onOpenChange={(open) => handleFlyoutOpenChange(cat.label, open)}
                label={cat.label}
              >
                <div>
                  <ToolCategory
                    activeTool={cat.activeTool}
                    isActive={isCategoryActive(cat)}
                    onToolClick={handleToolSelect}
                    onFlyoutOpen={() => handleFlyoutOpen(cat.label)}
                    label={cat.label}
                  />
                </div>
              </ToolFlyout>
            ))}
          </Toolbar.Group>

          <Toolbar.Separator />

          {/* Drawing mode controls */}
          <Toolbar.Group>
            {onMagnetToggle !== undefined && (
              <Tooltip content={magnetEnabled ? 'Magnet on' : 'Magnet off'} side="right">
                <IconButton
                  icon={<MagnetIcon />}
                  label={magnetEnabled ? 'Magnet on' : 'Magnet off'}
                  variant="ghost"
                  size="sm"
                  active={magnetEnabled}
                  onClick={() => onMagnetToggle(!magnetEnabled)}
                />
              </Tooltip>
            )}
            {onStayInDrawingModeToggle !== undefined && (
              <Tooltip content="Stay in drawing mode" side="right">
                <IconButton
                  icon={<PencilIcon />}
                  label="Stay in drawing mode"
                  variant="ghost"
                  size="sm"
                  active={stayInDrawingMode}
                  onClick={() => onStayInDrawingModeToggle(!stayInDrawingMode)}
                />
              </Tooltip>
            )}
            {onLockDrawingsToggle !== undefined && (
              <Tooltip content={drawingsLocked ? 'Unlock all drawings' : 'Lock all drawings'} side="right">
                <IconButton
                  icon={drawingsLocked ? <LockIcon /> : <UnlockIcon />}
                  label={drawingsLocked ? 'Unlock all drawings' : 'Lock all drawings'}
                  variant="ghost"
                  size="sm"
                  active={drawingsLocked}
                  onClick={() => onLockDrawingsToggle(!drawingsLocked)}
                />
              </Tooltip>
            )}
          </Toolbar.Group>

          {onRemoveAllDrawings !== undefined && (
            <>
              <Toolbar.Separator />
              <Toolbar.Group>
                <Tooltip content="Remove all drawings" side="right">
                  <IconButton
                    icon={<TrashIcon />}
                    label="Remove all drawings"
                    variant="ghost"
                    size="sm"
                    onClick={onRemoveAllDrawings}
                  />
                </Tooltip>
              </Toolbar.Group>
            </>
          )}
        </div>
      </Toolbar>
    );
  },
);

LeftToolbar.displayName = 'LeftToolbar';

/* ----- Inline icon components (avoiding lucide-react import bloat) -------- */

