import { useState, useCallback, useMemo, useEffect, useRef, type CSSProperties } from 'react';
import '@deskmodal/ui-components/tokens/brand.css';
import '@deskmodal/ui-components/tokens/brand-light.css';
import '@deskmodal/ui-components/tokens/deskmodal-bridge.css';
import '@deskmodal/ui-components/tokens/components.css';
import '@deskmodal/ui-components/tokens/components-light.css';
import { AppShell, AppHeader, ErrorBoundary, Toaster, toast } from '@deskmodal/ui-components';
import { useStateResetNotification } from '../../shared/hooks/use-state-reset-notification';
import { useSessionPersistence } from '../../shared/hooks/use-session-persistence';
import { Ticket } from 'lucide-react';
import { useInstrument, useFdc3, useContextListener, useRaiseIntent, INTENTS } from '@deskmodal/fdc3';
import type { OrderRequestContext, OrderModifyContext } from '@deskmodal/fdc3';
import { PriceDisplay } from './components/PriceDisplay';
import { SizeInput } from './components/SizeInput';
import { PriceInput } from './components/PriceInput';
import { OrderTypeSelect } from './components/OrderTypeSelect';
import { TradingModeToggle } from './components/TradingModeToggle';
import type { TradingMode } from './components/TradingModeToggle';
import { KillSwitch } from './components/KillSwitch';
import type { OrderType, TimeInForce, OrderSide } from './types';

/* -------------------------------------------------------------------------- */
/*  Exchanges                                                                 */
/* -------------------------------------------------------------------------- */

const EXCHANGES = [
  { id: 'binance', name: 'Binance' },
  { id: 'coinbase', name: 'Coinbase' },
  { id: 'bybit', name: 'Bybit' },
  { id: 'okx', name: 'OKX' },
  { id: 'kraken', name: 'Kraken' },
  { id: 'gemini', name: 'Gemini' },
];

/* -------------------------------------------------------------------------- */
/*  Styles                                                                    */
/* -------------------------------------------------------------------------- */

const wrapStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  overflow: 'auto',
  padding: 'var(--ts-space-3, 12px)',
  gap: 'var(--ts-space-3, 12px)',
  maxWidth: 420,
  margin: '0 auto',
  width: '100%',
  boxSizing: 'border-box',
};

const symbolBarStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2, 8px)',
  padding: 'var(--ts-space-2, 8px) var(--ts-space-3, 12px)',
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  border: '1px solid var(--ts-panel-border, #374151)',
};

const symbolSelectStyle: CSSProperties = {
  flex: 1,
  background: 'transparent',
  border: 'none',
  color: 'var(--ts-text-primary, #e5e7eb)',
  fontSize: 'var(--ts-font-md, 14px)',
  fontWeight: 600,
  fontFamily: 'var(--ts-watchlist-price-font, monospace)',
  outline: 'none',
  cursor: 'pointer',
};

const exchangeSelectStyle: CSSProperties = {
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  border: '1px solid var(--ts-panel-border, #374151)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  color: 'var(--ts-text-secondary, #9ca3af)',
  fontSize: 'var(--ts-font-xs, 11px)',
  padding: '4px 8px',
  outline: 'none',
  cursor: 'pointer',
};

const sideBtnRow: CSSProperties = {
  display: 'grid',
  gridTemplateColumns: '1fr 1fr',
  gap: 'var(--ts-space-2, 8px)',
};

const sideBtnBase: CSSProperties = {
  padding: '10px',
  border: '2px solid transparent',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  fontSize: 'var(--ts-font-md, 14px)',
  fontWeight: 700,
  letterSpacing: '0.06em',
  cursor: 'pointer',
  transition: 'all 120ms',
  textTransform: 'uppercase',
};

const sectionLabel: CSSProperties = {
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 600,
  color: 'var(--ts-text-secondary, #9ca3af)',
  textTransform: 'uppercase',
  letterSpacing: '0.04em',
};

const ocoSectionStyle: CSSProperties = {
  padding: 'var(--ts-space-3, 12px)',
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  border: '1px solid var(--ts-panel-border, #374151)',
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-2, 8px)',
};

const ocoHeaderStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 600,
  color: 'var(--ts-accent-default, #3b82f6)',
  textTransform: 'uppercase',
  letterSpacing: '0.04em',
};

const checkboxRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2, 8px)',
  fontSize: 'var(--ts-font-sm, 13px)',
  color: 'var(--ts-text-secondary, #9ca3af)',
  cursor: 'pointer',
};

const placeOrderBtnStyle: CSSProperties = {
  width: '100%',
  padding: '14px',
  border: 'none',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  fontSize: 'var(--ts-font-md, 14px)',
  fontWeight: 700,
  letterSpacing: '0.04em',
  cursor: 'pointer',
  transition: 'opacity 120ms',
};

const resetBtnStyle: CSSProperties = {
  width: '100%',
  padding: '8px',
  border: '1px solid var(--ts-panel-border, #374151)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  background: 'transparent',
  color: 'var(--ts-text-secondary, #9ca3af)',
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 600,
  letterSpacing: '0.06em',
  textTransform: 'uppercase',
  cursor: 'pointer',
};

const pipsHintStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 500,
};

const feedbackMsgStyle: CSSProperties = {
  padding: 'var(--ts-space-2, 8px)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 600,
  textAlign: 'center',
};

const rejectionStyle: CSSProperties = {
  ...feedbackMsgStyle,
  background: 'rgba(239, 68, 68, 0.12)',
  border: '1px solid rgba(239, 68, 68, 0.3)',
  color: 'var(--ts-price-change-down-text, #ef4444)',
};

const confirmationStyle: CSSProperties = {
  ...feedbackMsgStyle,
  background: 'rgba(34, 197, 94, 0.12)',
  border: '1px solid rgba(34, 197, 94, 0.3)',
  color: 'var(--ts-price-change-up-text, #22c55e)',
};

const balanceBarStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: 'var(--ts-space-1, 4px) var(--ts-space-2, 8px)',
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  border: '1px solid var(--ts-panel-border, #374151)',
  fontSize: 'var(--ts-font-xs, 11px)',
};

const balanceLabelStyle: CSSProperties = {
  color: 'var(--ts-text-secondary, #9ca3af)',
  fontWeight: 500,
};

const balanceValueStyle: CSSProperties = {
  color: 'var(--ts-text-primary, #e5e7eb)',
  fontWeight: 600,
  fontFamily: 'var(--ts-font-data, monospace)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
};

/* -------------------------------------------------------------------------- */
/*  App Component                                                             */
/* -------------------------------------------------------------------------- */

export function App(): React.JSX.Element {
  useStateResetNotification((msg) => toast.info({ title: msg, duration: 3000 }));

  const instrument = useInstrument();
  const fdc3 = useFdc3();
  const { raiseIntent } = useRaiseIntent();

  // --- State ---
  const [symbol, setSymbol] = useState('BTC/USDT');
  const [exchange, setExchange] = useState('binance');
  const [side, setSide] = useState<OrderSide>('buy');
  const [size, setSize] = useState(0);
  const [orderType, setOrderType] = useState<OrderType>('limit');
  const [timeInForce, setTimeInForce] = useState<TimeInForce>('GTC');
  const [limitPrice, setLimitPrice] = useState(0);
  const [stopPrice, setStopPrice] = useState(0);
  // OCO second leg
  const [ocoLimitPrice, setOcoLimitPrice] = useState(0);
  const [ocoStopPrice, setOcoStopPrice] = useState(0);
  // If Done: parent order triggers child
  const [ifDoneChildType, setIfDoneChildType] = useState<'limit' | 'stop'>('limit');
  const [ifDoneChildPrice, setIfDoneChildPrice] = useState(0);
  // Price alert
  const [addAlert, setAddAlert] = useState(false);
  // Trading mode
  const [tradingMode, setTradingMode] = useState<TradingMode>('paper');

  // Simulated bid/ask (in real app these come from a price feed)
  const [bid, setBid] = useState(0);
  const [ask, setAsk] = useState(0);

  // Order feedback state
  const [rejectionMsg, setRejectionMsg] = useState<string | null>(null);
  const [confirmationMsg, setConfirmationMsg] = useState<string | null>(null);
  const rejectionTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const confirmationTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Balance state (keyed by exchange)
  const [balances, setBalances] = useState<Map<string, { total: number; available: number; locked: number }>>(new Map());

  // Session persistence for dock/undock state survival
  useSessionPersistence(
    'deskmodal:order-ticket:session',
    1,
    { symbol, exchange, side, size, orderType, timeInForce, limitPrice, stopPrice, tradingMode },
    (saved) => {
      if (saved.symbol) setSymbol(saved.symbol as string);
      if (saved.exchange) setExchange(saved.exchange as string);
      if (saved.side) setSide(saved.side as OrderSide);
      if (typeof saved.size === 'number') setSize(saved.size);
      if (saved.orderType) setOrderType(saved.orderType as OrderType);
      if (saved.timeInForce) setTimeInForce(saved.timeInForce as TimeInForce);
      if (typeof saved.limitPrice === 'number' && saved.limitPrice > 0) setLimitPrice(saved.limitPrice);
      if (typeof saved.stopPrice === 'number' && saved.stopPrice > 0) setStopPrice(saved.stopPrice);
      if (saved.tradingMode) setTradingMode(saved.tradingMode as TradingMode);
    },
    [symbol, exchange, side, size, orderType, timeInForce, limitPrice, stopPrice, tradingMode],
  );

  // --- FDC3: update symbol when instrument changes on channel ---
  useEffect(() => {
    if (!instrument) return;
    const ticker = instrument.id?.ticker;
    if (ticker) {
      // Convert BTCUSDT → BTC/USDT if no slash present
      const formatted = ticker.includes('/') ? ticker : autoInsertSlash(ticker);
      setSymbol(formatted);
      // Set exchange if provided
      const exId = instrument.id?.exchange;
      if (exId && EXCHANGES.some((e) => e.id === exId)) {
        setExchange(exId);
      }
      // Use price from context if available
      const cryptoExt = (instrument as unknown as Record<string, unknown>)?.['deskmodal.crypto'] as
        | Record<string, unknown>
        | undefined;
      if (cryptoExt) {
        // Additional context may carry last price data
      }
    }
  }, [instrument]);

  // --- FDC3: receive order request from chart (right-click "Buy/Sell Limit at...") ---
  useContextListener<OrderRequestContext>('deskmodal.orderRequest', useCallback((ctx) => {
    if (ctx === null) return;
    const ticker = ctx.instrument?.ticker;
    if (ticker) {
      const formatted = ticker.includes('/') ? ticker : autoInsertSlash(ticker);
      setSymbol(formatted);
    }
    if (ctx.side) {
      setSide(ctx.side);
    }
    if (ctx.price !== undefined && ctx.price > 0) {
      setLimitPrice(ctx.price);
      setOrderType('limit');
    }
    if (ctx.exchange && EXCHANGES.some((e) => e.id === ctx.exchange)) {
      setExchange(ctx.exchange!);
    }
    if (ctx.size !== undefined && ctx.size > 0) {
      setSize(ctx.size);
    }
  }, []));

  // --- FDC3: receive order modification from chart (drag SL/TP/price) ---
  useContextListener<OrderModifyContext>('deskmodal.orderModify', useCallback((ctx) => {
    if (ctx === null) return;
    const field = ctx.field;
    const newValue = ctx.newValue;
    if (typeof newValue !== 'number' || newValue <= 0) return;

    if (field === 'limitPrice' || field === 'price') {
      setLimitPrice(newValue);
    } else if (field === 'stopLoss') {
      setStopPrice(newValue);
    }
  }, []));

  // --- FDC3: listen for order rejections from the paper trading service ---
  useContextListener<{ type: string; orderId: string; reason: string }>(
    'deskmodal.orderReject',
    useCallback((ctx) => {
      if (ctx === null) return;
      const msg = `Order rejected: ${ctx.reason}`;
      setRejectionMsg(msg);
      toast.error({ title: msg, duration: 3000 });
      if (rejectionTimer.current) clearTimeout(rejectionTimer.current);
      rejectionTimer.current = setTimeout(() => setRejectionMsg(null), 3000);
    }, [])
  );

  // --- FDC3: listen for balance updates from the paper trading service ---
  useContextListener<{ type: string; exchange: string; total: number; available: number; locked: number }>(
    'deskmodal.balance',
    useCallback((ctx) => {
      if (ctx === null) return;
      setBalances(prev => new Map(prev).set(ctx.exchange, {
        total: ctx.total,
        available: ctx.available,
        locked: ctx.locked,
      }));
    }, [])
  );

  // --- FDC3: listen for order confirmations (status updates) ---
  useContextListener<{ type: string; orderId: string; status: string; symbol: string; side: string; orderType: string }>(
    'deskmodal.order',
    useCallback((ctx) => {
      if (ctx === null) return;
      if (ctx.status === 'Working') {
        const msg = `Order working: ${ctx.symbol} ${ctx.orderType ?? ''} ${ctx.side ?? ''}`.trim();
        setConfirmationMsg(msg);
        toast.success({ title: msg, duration: 3000 });
        if (confirmationTimer.current) clearTimeout(confirmationTimer.current);
        confirmationTimer.current = setTimeout(() => setConfirmationMsg(null), 3000);
      }
    }, [])
  );

  // Simulated live prices (tick every second with small random moves)
  useEffect(() => {
    // Seed with a base price for known symbols
    const basePrices: Record<string, number> = {
      'BTC/USDT': 67500,
      'ETH/USDT': 3450,
      'SOL/USDT': 185,
      'BNB/USDT': 610,
      'XRP/USDT': 0.62,
    };
    const base = basePrices[symbol] ?? 100;
    const spread = base * 0.0002; // 2 bps spread
    setBid(base);
    setAsk(base + spread);
    setLimitPrice(base);
    setStopPrice(base);

    const interval = setInterval(() => {
      setBid((prev) => {
        const delta = (Math.random() - 0.5) * base * 0.0001;
        const newBid = prev + delta;
        setAsk(newBid + spread);
        return newBid;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [symbol]);

  // Derived
  const spreadPips = useMemo(() => {
    if (!bid || !ask) return 0;
    const precision = derivePrecision(bid);
    return Math.round((ask - bid) * Math.pow(10, precision));
  }, [bid, ask]);

  const pipsFromBid = useMemo(() => {
    if (!bid || !limitPrice) return 0;
    const precision = derivePrecision(bid);
    return Math.round((limitPrice - bid) * Math.pow(10, precision));
  }, [bid, limitPrice]);

  const tickSize = useMemo(() => {
    const precision = derivePrecision(bid || 100);
    return 1 / Math.pow(10, precision);
  }, [bid]);

  // --- Handlers ---
  const handleReset = useCallback(() => {
    setSize(0);
    setLimitPrice(bid);
    setStopPrice(bid);
    setOcoLimitPrice(0);
    setOcoStopPrice(0);
    setIfDoneChildPrice(0);
    setAddAlert(false);
  }, [bid]);

  const handleModeChange = useCallback((newMode: TradingMode) => {
    setTradingMode(newMode);
    if (fdc3) {
      fdc3.broadcast({
        type: 'deskmodal.tradingMode',
        mode: newMode,
      } as never).catch(() => {});
    }
  }, [fdc3]);

  const handleKillSwitch = useCallback(() => {
    if (!fdc3) return;
    fdc3.broadcast({
      type: 'deskmodal.killSwitch',
      timestamp: new Date().toISOString(),
    } as never).catch(() => {});
  }, [fdc3]);

  const handlePlaceOrder = useCallback(() => {
    if (!fdc3) {
      setRejectionMsg('FDC3 not available — waiting for desktop agent connection');
      setTimeout(() => setRejectionMsg(null), 3000);
      return;
    }
    const orderId = `ORD-${Date.now()}`;
    const orderPayload = {
      type: 'deskmodal.order' as const,
      id: { orderId },
      symbol,
      exchange,
      side,
      size,
      orderType,
      timeInForce,
      limitPrice: orderType !== 'market' ? limitPrice : undefined,
      stopPrice: ['stop', 'oco'].includes(orderType) ? stopPrice : undefined,
      oco: orderType === 'oco' ? { limitPrice: ocoLimitPrice, stopPrice: ocoStopPrice } : undefined,
      ifDone: orderType === 'if-done'
        ? { childType: ifDoneChildType, childPrice: ifDoneChildPrice }
        : undefined,
      addAlert,
      tradingMode,
      // Include current prices so paper trading engine can fill market orders immediately
      bid: bid || undefined,
      ask: ask || undefined,
    };
    // Broadcast the order on the channel so the blotter can pick it up
    fdc3.broadcast(orderPayload as never).catch(() => {});

    // Raise the PlaceOrder intent for the paper trading service
    raiseIntent(INTENTS.PlaceOrder, {
      type: 'deskmodal.orderRequest',
      id: { orderId },
      symbol,
      exchange,
      side,
      size,
      orderType,
      timeInForce,
      limitPrice: orderType !== 'market' ? limitPrice : undefined,
      stopPrice: ['stop', 'oco'].includes(orderType) ? stopPrice : undefined,
      oco: orderType === 'oco' ? { limitPrice: ocoLimitPrice, stopPrice: ocoStopPrice } : undefined,
      ifDone: orderType === 'if-done'
        ? { childType: ifDoneChildType, childPrice: ifDoneChildPrice }
        : undefined,
      tradingMode,
      bid: bid || undefined,
      ask: ask || undefined,
    } as never).then(() => {
      setConfirmationMsg(`${side === 'buy' ? 'Buy' : 'Sell'} ${size} ${symbol} — Order sent`);
      setTimeout(() => setConfirmationMsg(null), 3000);
    }).catch((err) => {
      const msg = err instanceof Error ? err.message : String(err);
      setRejectionMsg(msg || 'Order failed — no handler available');
      setTimeout(() => setRejectionMsg(null), 3000);
    });
  }, [
    fdc3, raiseIntent, symbol, exchange, side, size, orderType, timeInForce,
    limitPrice, stopPrice, ocoLimitPrice, ocoStopPrice,
    ifDoneChildType, ifDoneChildPrice, addAlert, bid, ask, tradingMode,
  ]);

  // --- Side button styles ---
  const sellBtnStyle: CSSProperties = {
    ...sideBtnBase,
    background: side === 'sell' ? 'var(--ts-price-change-down-text, #ef4444)' : 'var(--ts-surface-secondary, #1e1e2e)',
    color: side === 'sell' ? '#fff' : 'var(--ts-price-change-down-text, #ef4444)',
    borderColor: side === 'sell' ? 'var(--ts-price-change-down-text, #ef4444)' : 'var(--ts-panel-border, #374151)',
  };

  const buyBtnStyle: CSSProperties = {
    ...sideBtnBase,
    background: side === 'buy' ? 'var(--ts-price-change-up-text, #22c55e)' : 'var(--ts-surface-secondary, #1e1e2e)',
    color: side === 'buy' ? '#fff' : 'var(--ts-price-change-up-text, #22c55e)',
    borderColor: side === 'buy' ? 'var(--ts-price-change-up-text, #22c55e)' : 'var(--ts-panel-border, #374151)',
  };

  const placeColor = side === 'buy'
    ? 'var(--ts-price-change-up-text, #22c55e)'
    : 'var(--ts-price-change-down-text, #ef4444)';

  const showLimitPrice = orderType !== 'market';
  const showStopPrice = orderType === 'stop' || orderType === 'oco' || orderType === 'if-done';
  const showOco = orderType === 'oco';
  const showIfDone = orderType === 'if-done';

  return (
    <ErrorBoundary level="app">
      <AppShell
        header={
          <AppHeader
            title="Order Ticket"
            icon={<Ticket size={16} />}
          />
        }
      >
        <div style={wrapStyle}>
          {/* Trading mode + Kill switch */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ts-space-2, 8px)' }}>
            <TradingModeToggle
              mode={tradingMode}
              onModeChange={handleModeChange}
              exchange={EXCHANGES.find((e) => e.id === exchange)?.name ?? exchange}
            />
            <KillSwitch
              visible={tradingMode === 'live'}
              onKill={handleKillSwitch}
            />
          </div>

          {/* Symbol selector + Exchange */}
          <div style={{ display: 'flex', gap: 'var(--ts-space-2, 8px)' }}>
            <div style={{ ...symbolBarStyle, flex: 1 }}>
              <SearchIcon />
              <input
                type="text"
                value={symbol}
                onChange={(e) => setSymbol(e.target.value.toUpperCase())}
                style={symbolSelectStyle}
                aria-label="Symbol"
              />
            </div>
            <select
              value={exchange}
              onChange={(e) => setExchange(e.target.value)}
              style={exchangeSelectStyle}
              aria-label="Exchange"
            >
              {EXCHANGES.map((ex) => (
                <option key={ex.id} value={ex.id}>{ex.name}</option>
              ))}
            </select>
          </div>

          {/* Bid / Spread / Ask */}
          <PriceDisplay bid={bid} ask={ask} spread={spreadPips} />

          {/* SELL / BUY */}
          <div style={sideBtnRow}>
            <button type="button" style={sellBtnStyle} onClick={() => setSide('sell')}>
              SELL
            </button>
            <button type="button" style={buyBtnStyle} onClick={() => setSide('buy')}>
              BUY
            </button>
          </div>

          {/* Size */}
          <div>
            <div style={sectionLabel}>Size</div>
            <SizeInput value={size} onChange={setSize} />
          </div>

          {/* Reset */}
          <button type="button" style={resetBtnStyle} onClick={handleReset}>
            RESET
          </button>

          {/* Order type + TIF */}
          <OrderTypeSelect
            orderType={orderType}
            onOrderTypeChange={setOrderType}
            timeInForce={timeInForce}
            onTimeInForceChange={setTimeInForce}
          />

          {/* Limit price */}
          {showLimitPrice && (
            <div>
              <div style={sectionLabel}>
                {orderType === 'oco' ? 'Take Profit Price' : 'Limit Price'}
              </div>
              <PriceInput value={limitPrice} onChange={setLimitPrice} step={tickSize} />
              <div
                style={{
                  ...pipsHintStyle,
                  color: pipsFromBid < 0
                    ? 'var(--ts-price-change-down-text, #ef4444)'
                    : 'var(--ts-price-change-up-text, #22c55e)',
                  marginTop: '4px',
                }}
              >
                {pipsFromBid >= 0 ? '+' : ''}{pipsFromBid} pips from bid
              </div>
            </div>
          )}

          {/* Stop price */}
          {showStopPrice && (
            <div>
              <div style={sectionLabel}>Stop Price</div>
              <PriceInput value={stopPrice} onChange={setStopPrice} step={tickSize} />
            </div>
          )}

          {/* OCO: second leg */}
          {showOco && (
            <div style={ocoSectionStyle}>
              <div style={ocoHeaderStyle}>OCO — Second Leg</div>
              <div>
                <div style={sectionLabel}>Stop Loss Price</div>
                <PriceInput value={ocoStopPrice} onChange={setOcoStopPrice} step={tickSize} />
              </div>
            </div>
          )}

          {/* If Done: child order */}
          {showIfDone && (
            <div style={ocoSectionStyle}>
              <div style={ocoHeaderStyle}>If Done — Child Order</div>
              <div style={{ display: 'flex', gap: 'var(--ts-space-2, 8px)' }}>
                <div style={{ flex: 1 }}>
                  <div style={sectionLabel}>Child Type</div>
                  <select
                    value={ifDoneChildType}
                    onChange={(e) => setIfDoneChildType(e.target.value as 'limit' | 'stop')}
                    style={{ ...exchangeSelectStyle, width: '100%' }}
                  >
                    <option value="limit">Limit</option>
                    <option value="stop">Stop</option>
                  </select>
                </div>
                <div style={{ flex: 1 }}>
                  <div style={sectionLabel}>Child Price</div>
                  <PriceInput value={ifDoneChildPrice} onChange={setIfDoneChildPrice} step={tickSize} />
                </div>
              </div>
            </div>
          )}

          {/* Alert checkbox */}
          <label style={checkboxRowStyle}>
            <input
              type="checkbox"
              checked={addAlert}
              onChange={(e) => setAddAlert(e.target.checked)}
              style={{ accentColor: 'var(--ts-accent-default, #3b82f6)' }}
            />
            <AlertIcon />
            Add price alert at{' '}
            {orderType === 'stop' ? 'stop' : 'limit'} price
          </label>

          {/* Available balance for selected exchange */}
          {balances.has(exchange) && (
            <div style={balanceBarStyle} data-ts-order-balance="">
              <span style={balanceLabelStyle}>Available</span>
              <span style={balanceValueStyle}>
                {balances.get(exchange)!.available.toLocaleString(undefined, {
                  minimumFractionDigits: 2,
                  maximumFractionDigits: 2,
                })} USDT
              </span>
            </div>
          )}

          {/* Order rejection feedback */}
          {rejectionMsg && (
            <div style={rejectionStyle} data-ts-order-rejection="" role="alert">
              {rejectionMsg}
            </div>
          )}

          {/* Order confirmation feedback */}
          {confirmationMsg && (
            <div style={confirmationStyle} data-ts-order-confirmation="" role="status">
              {confirmationMsg}
            </div>
          )}

          {/* Place Order */}
          <button
            type="button"
            style={{
              ...placeOrderBtnStyle,
              background: placeColor,
              color: '#fff',
              opacity: size > 0 ? 1 : 0.5,
            }}
            disabled={size <= 0}
            onClick={handlePlaceOrder}
          >
            {tradingMode === 'live' ? 'LIVE ' : ''}Place {side === 'buy' ? 'Buy' : 'Sell'} Order
          </button>
        </div>
        <Toaster position="bottom-right" theme="dark" />
      </AppShell>
    </ErrorBoundary>
  );
}

