/* -------------------------------------------------------------------------- */
/*  Helpers                                                                   */
/* -------------------------------------------------------------------------- */

function derivePrecision(price: number): number {
  if (price >= 1000) return 2;
  if (price >= 1) return 4;
  return 6;
}

function autoInsertSlash(pair: string): string {
  const BASES = [
    'BTC', 'ETH', 'SOL', 'BNB', 'XRP', 'ADA', 'AVAX', 'DOT', 'LINK',
    'MATIC', 'DOGE', 'SHIB', 'UNI', 'LTC', 'ATOM', 'NEAR', 'ARB',
    'OP', 'APT', 'SUI', 'FIL', 'AAVE', 'MKR', 'GBP', 'EUR', 'USD',
    'AUD', 'NZD', 'CAD', 'CHF', 'JPY', 'ZAR', 'SEK', 'NOK',
  ];
  for (const base of BASES) {
    if (pair.startsWith(base) && pair.length > base.length) {
      return `${base}/${pair.slice(base.length)}`;
    }
  }
  if (pair.length >= 6) return `${pair.slice(0, 3)}/${pair.slice(3)}`;
  return pair;
}
