import { type ReactNode, type CSSProperties, forwardRef } from 'react';
import { Toolbar } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  ChartTopBar                                                               */
/*  Horizontal toolbar spanning the top of the chart app.                     */
/*  Slot-based layout: callers provide ReactNode content per group.           */
/*  Uses Toolbar primitive with --ts-toolbar-* tokens.                        */
/* -------------------------------------------------------------------------- */

export interface ChartTopBarProps {
  /** Content for the symbol/instrument group (left section). */
  symbolGroup?: ReactNode;
  /** Content for the timeframe section. */
  timeframeGroup?: ReactNode;
  /** Content for the date range section (1D, 5D, 1M, 1Y, All). */
  dateRangeGroup?: ReactNode;
  /** Content for the chart type section. */
  chartTypeGroup?: ReactNode;
  /** Content for the analysis tools section (indicators, templates). */
  analysisGroup?: ReactNode;
  /** Content for the alert/replay section. */
  alertReplayGroup?: ReactNode;
  /** Content for the undo/redo section. */
  historyGroup?: ReactNode;
  /** Content for the layout/save section. */
  layoutGroup?: ReactNode;
  /** Content for the utility section (search, settings, fullscreen, screenshot). */
  utilityGroup?: ReactNode;
  /** Whether to use compact mode (pane mode). Hides non-essential groups. */
  compact?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-chart-top-bar-styles';

function ensureChartTopBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-chart-top-bar] [data-ts-chart-top-bar-spacer] {
      flex: 1;
      min-width: 0;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureChartTopBarStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const wrapperStyle: CSSProperties = {
  display: 'contents',
};

/* ----- Component --------------------------------------------------------- */

export const ChartTopBar = forwardRef<HTMLDivElement, ChartTopBarProps>(
  function ChartTopBar(props, ref) {
    const {
      symbolGroup,
      timeframeGroup,
      dateRangeGroup,
      chartTypeGroup,
      analysisGroup,
      alertReplayGroup,
      historyGroup,
      layoutGroup,
      utilityGroup,
      compact = false,
    } = props;

    const leftGroups: { key: string; node: ReactNode }[] = [];

    if (symbolGroup !== undefined && symbolGroup !== null) {
      leftGroups.push({ key: 'symbol', node: symbolGroup });
    }
    if (timeframeGroup !== undefined && timeframeGroup !== null) {
      leftGroups.push({ key: 'timeframe', node: timeframeGroup });
    }
    if (dateRangeGroup !== undefined && dateRangeGroup !== null) {
      leftGroups.push({ key: 'dateRange', node: dateRangeGroup });
    }
    if (chartTypeGroup !== undefined && chartTypeGroup !== null) {
      leftGroups.push({ key: 'chartType', node: chartTypeGroup });
    }
    if (!compact) {
      if (analysisGroup !== undefined && analysisGroup !== null) {
        leftGroups.push({ key: 'analysis', node: analysisGroup });
      }
      if (alertReplayGroup !== undefined && alertReplayGroup !== null) {
        leftGroups.push({ key: 'alertReplay', node: alertReplayGroup });
      }
      if (historyGroup !== undefined && historyGroup !== null) {
        leftGroups.push({ key: 'history', node: historyGroup });
      }
      if (layoutGroup !== undefined && layoutGroup !== null) {
        leftGroups.push({ key: 'layout', node: layoutGroup });
      }
    }

    const hasUtility = utilityGroup !== undefined && utilityGroup !== null;

    return (
      <Toolbar ref={ref}>
        <div data-ts-chart-top-bar="" style={wrapperStyle}>
          {leftGroups.map((group, index) => (
            <Toolbar.Group key={group.key}>
              {index > 0 && <Toolbar.Separator />}
              {group.node}
            </Toolbar.Group>
          ))}
          {hasUtility && (
            <>
              <div data-ts-chart-top-bar-spacer="" style={{ flex: 1, minWidth: 0 }} />
              <Toolbar.Group>
                {leftGroups.length > 0 && <Toolbar.Separator />}
                {utilityGroup}
              </Toolbar.Group>
            </>
          )}
        </div>
      </Toolbar>
    );
  },
);

ChartTopBar.displayName = 'ChartTopBar';
