import { forwardRef, type CSSProperties } from 'react';
import { ArrowDownUp } from 'lucide-react';
import { Panel, Toolbar, Select, EmptyState } from '../../primitives';
import { MetricCard } from './MetricCard';

/* -------------------------------------------------------------------------- */
/*  ExchangeFlowPanel                                                         */
/*  Shows exchange inflow/outflow/netflow with controls and chart placeholder.*/
/*  Uses --ts-metric-card-* and --ts-viz-shell-* tokens.                      */
/* -------------------------------------------------------------------------- */

export type FlowTimePeriod = '24h' | '7d' | '30d' | '90d';
export type FlowViewMode = 'netflow' | 'inflow-outflow' | 'balance';

export interface ExchangeFlowPanelProps {
  /** Panel title. */
  title?: string;
  /** Current netflow value. */
  netflow: number;
  /** Change percentage. */
  changePercent: number;
  /** Inflow total. */
  inflowTotal: number;
  /** Outflow total. */
  outflowTotal: number;
  /** Currently selected time period. */
  timePeriod: FlowTimePeriod;
  /** Called when time period changes. */
  onTimePeriodChange: (period: FlowTimePeriod) => void;
  /** Currently selected view mode. */
  viewMode: FlowViewMode;
  /** Called when view mode changes. */
  onViewModeChange: (mode: FlowViewMode) => void;
  /** Called when the user clicks to view full chart. */
  onViewChart?: () => void;
  /** Asset selector. */
  asset: string;
  /** Available assets. */
  availableAssets: Array<{ value: string; label: string }>;
  /** Called when asset changes. */
  onAssetChange: (asset: string) => void;
}

/* ----- Constants --------------------------------------------------------- */

const TIME_PERIOD_OPTIONS: Array<{ value: FlowTimePeriod; label: string }> = [
  { value: '24h', label: '24H' },
  { value: '7d', label: '7D' },
  { value: '30d', label: '30D' },
  { value: '90d', label: '90D' },
];

const VIEW_MODE_OPTIONS: Array<{ value: FlowViewMode; label: string }> = [
  { value: 'netflow', label: 'Netflow' },
  { value: 'inflow-outflow', label: 'Inflow/Outflow' },
  { value: 'balance', label: 'Balance' },
];

/* ----- Styles ------------------------------------------------------------ */

const summaryRowStyle: CSSProperties = {
  display: 'grid',
  gridTemplateColumns: 'repeat(3, 1fr)',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-3)',
};

const vizContainerStyle: CSSProperties = {
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  background: 'var(--ts-viz-shell-bg)',
  minHeight: 200,
};

export const ExchangeFlowPanel = forwardRef<HTMLDivElement, ExchangeFlowPanelProps>(
  function ExchangeFlowPanel(
    {
      title = 'Exchange Flow',
      netflow,
      changePercent,
      inflowTotal,
      outflowTotal,
      timePeriod,
      onTimePeriodChange,
      viewMode,
      onViewModeChange,
      onViewChart,
      asset,
      availableAssets,
      onAssetChange,
    },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-exchange-flow-panel="">
        <Panel
          title={title}
          actions={
            <Select
              options={availableAssets}
              value={asset}
              onValueChange={onAssetChange}
              size="sm"
              label="Asset"
            />
          }
        >
          {/* Summary metrics */}
          <div style={summaryRowStyle}>
            <MetricCard
              label="Netflow"
              value={netflow}
              changePercent={changePercent}
              size="compact"
            />
            <MetricCard
              label="Inflow"
              value={inflowTotal}
              size="compact"
            />
            <MetricCard
              label="Outflow"
              value={outflowTotal}
              size="compact"
            />
          </div>

          {/* Controls */}
          <Toolbar>
            <Toolbar.Group>
              {TIME_PERIOD_OPTIONS.map((opt) => (
                <Toolbar.Item
                  key={opt.value}
                  active={timePeriod === opt.value}
                  onClick={() => onTimePeriodChange(opt.value)}
                  aria-label={`Time period ${opt.label}`}
                >
                  {opt.label}
                </Toolbar.Item>
              ))}
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              {VIEW_MODE_OPTIONS.map((opt) => (
                <Toolbar.Item
                  key={opt.value}
                  active={viewMode === opt.value}
                  onClick={() => onViewModeChange(opt.value)}
                  aria-label={`View mode ${opt.label}`}
                >
                  {opt.label}
                </Toolbar.Item>
              ))}
            </Toolbar.Group>

            {onViewChart !== undefined && (
              <>
                <Toolbar.Separator />
                <Toolbar.Group>
                  <Toolbar.Item
                    onClick={onViewChart}
                    aria-label="View full chart"
                  >
                    View Chart
                  </Toolbar.Item>
                </Toolbar.Group>
              </>
            )}
          </Toolbar>

          {/* Chart area placeholder */}
          <div style={vizContainerStyle}>
            <EmptyState
              icon={<ArrowDownUp size={40} />}
              title="Connect to data source"
              description="Exchange flow chart will render here when connected to market data."
            />
          </div>
        </Panel>
      </div>
    );
  },
);

ExchangeFlowPanel.displayName = 'ExchangeFlowPanel';
