import { forwardRef, type CSSProperties } from 'react';
import { Slider as SliderPrimitive } from 'radix-ui';

/* -------------------------------------------------------------------------- */
/*  Slider                                                                    */
/*  Range slider with track, range fill, and draggable thumb.                 */
/*  Wraps Radix Slider — uses --ts-slider-* tokens.                           */
/* -------------------------------------------------------------------------- */

export interface SliderProps {
  /** Current value(s). Single number or array for range. */
  value?: number[];
  /** Called when the value changes. */
  onValueChange?: (value: number[]) => void;
  /** Minimum value. */
  min?: number;
  /** Maximum value. */
  max?: number;
  /** Step increment. */
  step?: number;
  /** Whether the slider is disabled. */
  disabled?: boolean;
  /** Accessible label. */
  label?: string;
}

/* ----- Style injection for hover/active states --------------------------- */

const SLIDER_STYLE_ID = 'ts-slider-styles';

function ensureSliderStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(SLIDER_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = SLIDER_STYLE_ID;
  sheet.textContent = `
    [data-ts-slider-thumb]:hover {
      background: var(--ts-slider-thumb-bg-hover);
    }
    [data-ts-slider-thumb]:active,
    [data-ts-slider-thumb][data-state="grabbing"] {
      background: var(--ts-slider-thumb-bg-active);
    }
    [data-ts-slider-thumb]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-slider][data-disabled] [data-ts-slider-thumb] {
      cursor: not-allowed;
      opacity: 0.5;
    }
    [data-ts-slider][data-disabled] {
      opacity: 0.5;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureSliderStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  position: 'relative',
  display: 'flex',
  alignItems: 'center',
  userSelect: 'none',
  touchAction: 'none',
  width: '100%',
  height: 20,
};

const trackStyle: CSSProperties = {
  background: 'var(--ts-slider-track-bg)',
  position: 'relative',
  flexGrow: 1,
  borderRadius: 'calc(var(--ts-slider-track-height) / 2)',
  height: 'var(--ts-slider-track-height)',
};

const rangeStyle: CSSProperties = {
  position: 'absolute',
  background: 'var(--ts-slider-range-bg)',
  borderRadius: 'inherit',
  height: '100%',
};

const thumbStyle: CSSProperties = {
  display: 'block',
  width: 'var(--ts-slider-thumb-size)',
  height: 'var(--ts-slider-thumb-size)',
  background: 'var(--ts-slider-thumb-bg)',
  border: '2px solid var(--ts-slider-thumb-border)',
  borderRadius: '50%',
  boxShadow: 'var(--ts-slider-thumb-shadow)',
  cursor: 'grab',
  transition: 'background 150ms',
  boxSizing: 'border-box',
};

export const Slider = forwardRef<HTMLSpanElement, SliderProps>(
  function Slider(
    { value, onValueChange, min = 0, max = 100, step = 1, disabled = false, label },
    ref,
  ) {
    return (
      <SliderPrimitive.Root
        ref={ref}
        data-ts-slider=""
        {...(disabled ? { 'data-disabled': '' } : {})}
        value={value}
        onValueChange={onValueChange}
        min={min}
        max={max}
        step={step}
        disabled={disabled}
        aria-label={label}
        style={rootStyle}
      >
        <SliderPrimitive.Track style={trackStyle}>
          <SliderPrimitive.Range style={rangeStyle} />
        </SliderPrimitive.Track>
        {(value ?? [min]).map((_, i) => (
          <SliderPrimitive.Thumb key={i} data-ts-slider-thumb="" style={thumbStyle} />
        ))}
      </SliderPrimitive.Root>
    );
  },
);

Slider.displayName = 'Slider';
