import { useMemo, type CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  PriceDisplay — Bid / Spread / Ask tile like the screenshot                */
/* -------------------------------------------------------------------------- */

interface PriceDisplayProps {
  bid: number;
  ask: number;
  spread: number; // in pips
}

const wrapStyle: CSSProperties = {
  display: 'grid',
  gridTemplateColumns: '1fr auto 1fr',
  alignItems: 'center',
  background: 'var(--ts-surface-secondary, #1e1e2e)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  border: '1px solid var(--ts-panel-border, #374151)',
  overflow: 'hidden',
};

const priceColStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  padding: 'var(--ts-space-2, 8px) var(--ts-space-3, 12px)',
  gap: '2px',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 500,
  textTransform: 'uppercase',
  letterSpacing: '0.04em',
};

const spreadBadgeStyle: CSSProperties = {
  padding: '2px 6px',
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 600,
  fontFamily: 'var(--ts-watchlist-price-font, monospace)',
  background: 'var(--ts-surface-primary, #111827)',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  border: '1px solid var(--ts-panel-border, #374151)',
  color: 'var(--ts-text-primary, #e5e7eb)',
};

const dividerStyle: CSSProperties = {
  width: '1px',
  alignSelf: 'stretch',
  background: 'var(--ts-panel-border, #374151)',
};

export function PriceDisplay({ bid, ask, spread }: PriceDisplayProps) {
  const { bidFormatted, askFormatted } = useMemo(() => {
    return {
      bidFormatted: formatBigFig(bid),
      askFormatted: formatBigFig(ask),
    };
  }, [bid, ask]);

  return (
    <div style={wrapStyle}>
      {/* Bid */}
      <div style={priceColStyle}>
        <span style={{ ...labelStyle, color: 'var(--ts-price-change-down-text, #ef4444)' }}>Bid</span>
        <PriceWithBigFig parts={bidFormatted} />
      </div>

      {/* Spread badge + divider */}
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', position: 'relative' }}>
        <div style={dividerStyle} />
        <span style={spreadBadgeStyle}>{spread}</span>
      </div>

      {/* Ask */}
      <div style={priceColStyle}>
        <span style={{ ...labelStyle, color: 'var(--ts-text-secondary, #9ca3af)' }}>Ask</span>
        <PriceWithBigFig parts={askFormatted} />
      </div>
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  Big-figure price rendering (like 22.79**65**0)                            */
/* -------------------------------------------------------------------------- */

interface PriceParts {
  prefix: string;
  bigFig: string;
  suffix: string;
}

function PriceWithBigFig({ parts }: { parts: PriceParts }) {
  return (
    <span style={{ fontFamily: 'var(--ts-watchlist-price-font, monospace)', whiteSpace: 'nowrap' }}>
      <span style={{ fontSize: 'var(--ts-font-sm, 13px)', color: 'var(--ts-text-primary, #e5e7eb)' }}>
        {parts.prefix}
      </span>
      <span style={{ fontSize: 'var(--ts-font-xl, 20px)', fontWeight: 700, color: 'var(--ts-text-primary, #e5e7eb)' }}>
        {parts.bigFig}
      </span>
      <span style={{ fontSize: 'var(--ts-font-sm, 13px)', color: 'var(--ts-text-secondary, #9ca3af)' }}>
        {parts.suffix}
      </span>
    </span>
  );
}

/**
 * Split a price into prefix (leading digits), big figure (2 actionable digits),
 * and suffix (trailing precision).
 */
function formatBigFig(price: number): PriceParts {
  if (price === 0) return { prefix: '0', bigFig: '.00', suffix: '' };

  const precision = price >= 1000 ? 3 : price >= 1 ? 5 : 7;
  const str = price.toFixed(precision);
  const dotIdx = str.indexOf('.');

  if (dotIdx === -1) {
    // Integer — big fig is last 2 digits
    if (str.length <= 2) return { prefix: '', bigFig: str, suffix: '' };
    return { prefix: str.slice(0, -2), bigFig: str.slice(-2), suffix: '' };
  }

  // Find the 2 most significant decimal digits for big fig
  // For FX-style: prefix is up to the pip boundary, big fig is 2 pip digits, suffix is rest
  const intPart = str.slice(0, dotIdx);
  const decPart = str.slice(dotIdx + 1);

  // Big fig position depends on magnitude
  let bigStart: number;
  if (price >= 100) {
    bigStart = 0; // big fig starts at first decimal digit
  } else if (price >= 1) {
    bigStart = 2; // e.g., 22.79**65**0
  } else {
    bigStart = 3;
  }

  const prefix = `${intPart}.${decPart.slice(0, bigStart)}`;
  const bigFig = decPart.slice(bigStart, bigStart + 2);
  const suffix = decPart.slice(bigStart + 2);

  return { prefix, bigFig, suffix };
}
