import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { ScrollArea } from '../../primitives';
import { MetricCard } from './MetricCard';

/* -------------------------------------------------------------------------- */
/*  MetricDashboard                                                           */
/*  Grid of MetricCards with responsive column layout.                        */
/*  Uses --ts-metric-card-* tokens via MetricCard.                            */
/* -------------------------------------------------------------------------- */

export interface MetricDashboardProps {
  /** Metric card configurations. */
  metrics: Array<{
    id: string;
    label: string;
    value: number;
    previousValue?: number;
    changePercent?: number;
    unit?: string;
    icon?: ReactNode;
    sparklineData?: number[];
    onClick?: () => void;
  }>;
  /** Number of columns in the grid (responsive default). */
  columns?: number;
  /** Whether all cards are loading. */
  loading?: boolean;
  /** Size variant for all cards. */
  size?: 'compact' | 'default';
}

/* ----- Styles ------------------------------------------------------------ */

function getGridStyle(columns?: number): CSSProperties {
  return {
    display: 'grid',
    gridTemplateColumns: columns !== undefined
      ? `repeat(${columns}, 1fr)`
      : 'repeat(auto-fill, minmax(200px, 1fr))',
    gap: 'var(--ts-space-3)',
    padding: 'var(--ts-space-1)',
  };
}

export const MetricDashboard = forwardRef<HTMLDivElement, MetricDashboardProps>(
  function MetricDashboard(
    { metrics, columns, loading = false, size = 'default' },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-metric-dashboard="">
        <ScrollArea>
          <div style={getGridStyle(columns)}>
            {metrics.map((metric) => (
              <MetricCard
                key={metric.id}
                label={metric.label}
                value={metric.value}
                previousValue={metric.previousValue}
                changePercent={metric.changePercent}
                unit={metric.unit}
                icon={metric.icon}
                sparklineData={metric.sparklineData}
                onClick={metric.onClick}
                loading={loading}
                size={size}
              />
            ))}
          </div>
        </ScrollArea>
      </div>
    );
  },
);

MetricDashboard.displayName = 'MetricDashboard';
